import { addresses, redeemPositionsCalldata } from '@prob/core'
import { numberToHex } from 'viem'
import type { BasicClobClient } from '../createClient'
import { proxyExecuteTx } from '../proxy/proxyExecuteTx'

export type RedeemPositionParams = {
  conditionId: `0x${string}`
  indexSets: bigint[]
}

export function redeemPosition(
  client: BasicClobClient,
  params: RedeemPositionParams,
) {
  const calldata = createRedeemPositionCalldata(client, params)
  return proxyExecuteTx(client, {
    to: addresses[client.chainId].conditionalTokens,
    data: calldata,
  })
}

export function createRedeemPositionCalldata(
  client: BasicClobClient,
  params: RedeemPositionParams,
) {
  const collateralToken = client.exchangeConfig.collateralToken

  return redeemPositionsCalldata({
    collateralToken,
    parentCollectionId: numberToHex(0, { size: 32 }),
    conditionId: params.conditionId,
    indexSets: params.indexSets,
  })
}
