import {
  getProbProxyWalletAddress,
  getSafeAddress,
  OrderStructSignatureType,
} from '@prob/core'
import type { Address } from 'viem'

export type GetMakerAddressParams = {
  chainId: number
  signer: Address
  signatureType: OrderStructSignatureType
}
export function getMakerAddress(params: GetMakerAddressParams) {
  const { chainId, signer, signatureType } = params
  switch (signatureType) {
    case OrderStructSignatureType.ProbProxy:
      return getProbProxyWalletAddress(chainId, signer)
    case OrderStructSignatureType.ProbGnosisSafe:
      return getSafeAddress(chainId, signer)
    case OrderStructSignatureType.Eoa:
      return signer
    default:
      throw new Error('Invalid signature type')
  }
}
