import { addresses, getSafeAddress } from '@prob/core'
import {
  type Address,
  encodeFunctionData,
  erc20Abi,
  type Hex,
  maxUint256,
} from 'viem'
import {
  getTransactionReceipt,
  readContract,
  waitForTransactionReceipt,
} from 'viem/actions'
import { executeSafeProxyTx } from '../../proxy/executeSafeProxyTx'
import type { BasicClobClient } from '../createClient'

export function createApproveCollateralCalldata({
  spender,
  allowanceAmount,
}: {
  spender: Address
  allowanceAmount: bigint
}): Hex {
  return encodeFunctionData({
    abi: erc20Abi,
    functionName: 'approve',
    args: [spender, allowanceAmount],
  })
}

export async function proxyApproveCollateral(
  client: BasicClobClient,
  amount?: bigint,
) {
  const collateralToken = client.exchangeConfig.collateralToken
  const txHash = await executeSafeProxyTx(client.wallet!, {
    to: collateralToken,
    data: createApproveCollateralCalldata({
      spender: addresses[client.chainId].conditionalTokens,
      allowanceAmount: amount ?? maxUint256,
    }),
  })
  return txHash
}

export async function proxyApproveCollateralSync(
  client: BasicClobClient,
  amount?: bigint,
) {
  const txHash = await proxyApproveCollateral(client, amount)
  // console.log('txHash', txHash)
  return waitForTransactionReceipt(client.wallet!, { hash: txHash })
}

export type ProxyApproveCollateralIfNeededParams = {
  allowanceAmount?: bigint
}

export async function proxyApproveCollateralIfNeeded(
  client: BasicClobClient,
  params?: ProxyApproveCollateralIfNeededParams,
) {
  const { allowanceAmount = maxUint256 } = params ?? {}
  const collateralToken = client.exchangeConfig.collateralToken
  const safeAddress = getSafeAddress(
    client.chainId,
    client.wallet!.account.address,
  )
  const allowance = await readContract(client.wallet!, {
    address: collateralToken,
    abi: erc20Abi,
    functionName: 'allowance',
    args: [safeAddress, addresses[client.chainId].conditionalTokens],
  })
  // console.log('proxy allowance to conditional tokens', allowance)
  if (allowance < allowanceAmount) {
    await proxyApproveCollateralSync(client, allowanceAmount)
  }
}
