export type TradingLimit = {
  /**
   * the minimum allowed size of order
   */
  minSize: number
  /**
   * the maximum allowed size of order
   */
  maxSize: number
  /**
   * all the size value should be a multiple of stepSize
   */
  stepSize: number
  /**
   * the minimum allowed price
   */
  minPrice: number
  /**
   * the maximum allowed price
   */
  maxPrice: number
  /**
   * all the price value should be a multiple of stepPrice
   */
  stepPrice: number
  /**
   * the minimum allowed notional
   *
   * minNotional = minPrice * minSize
   */
  minNotional: number
  /**
   * the maximum allowed notional
   *
   * maxNotional = maxPrice * maxSize
   */
  maxNotional: number
  /**
   * the minimum allowed market size
   */
  marketMinSize: number
  /**
   * the maximum allowed market size
   */
  marketMaxSize: number
  /**
   * the step amount for the market
   */
  marketStepSize: number
}

export const defaultTradingLimit: TradingLimit = {
  minSize: 1, // min shares per order can be traded
  maxSize: 1000000, // max shares per order can be traded
  stepSize: 0.01, // shares amount should be a multiple of stepSize
  minPrice: 0.001, // min price per share
  maxPrice: 0.999, // max price per share
  stepPrice: 0.001, // price per share should be a multiple of stepPrice
  marketMinSize: 1, // min size per market order can be traded
  marketMaxSize: 1000000, // max size per market order can be traded
  marketStepSize: 0.01, // size per market order should be a multiple of marketStepSize
  minNotional: 1, // min usd amount per order can be traded, ONLY validate when BUY order, if SELL order, it will be ignored
  maxNotional: 1000000000, // max usd amount per order can be traded, ONLY validate when BUY order, if SELL order, it will be ignored
}
