import type { BasicClobClient } from '../createClient'

export enum PnLInterval {
  ALL = 'all',
  ONE_MONTH = '1m',
  ONE_WEEK = '1w',
  ONE_DAY = '1d',
}

export enum PnLFidelity {
  ONE_DAY = '1d',
  EIGHTEEN_HOURS = '18h',
  TWELVE_HOURS = '12h',
  THREE_HOURS = '3h',
  ONE_HOUR = '1h',
}

export type GetPnLParams = {
  userAddress: string
  interval?: PnLInterval
  fidelity?: PnLFidelity
}

export type GetPnLResponse = Array<{
  t: number
  p: number
}>

export function getPnL(client: BasicClobClient, params: GetPnLParams) {
  const searchParams: Record<string, string> = {
    user_address: params.userAddress,
  }

  if (params.interval !== undefined) {
    searchParams.interval = params.interval
  }
  if (params.fidelity !== undefined) {
    searchParams.fidelity = params.fidelity
  }

  return client.httpClient
    .get<GetPnLResponse>(`pnl`, {
      searchParams,
    })
    .json()
}
