import { buildSearchParams } from '../..'
import type { BasicClobClient } from '../createClient'

export type PendingPosition = {
  outcome: string
  qty: number
  price: number
  side: 'Buy' | 'Sell'
  time: number
}

export type GetPendingPositionsParams = {
  /** The market ID (id field in markets table) */
  marketId: string | number
  /** User wallet address */
  user: string
  /** Optional timestamp parameter for filtering pending trades */
  timestamp?: string | number
}

export type GetPendingPositionsResponse = Array<PendingPosition>

export function getPendingPositions(
  client: BasicClobClient,
  params: GetPendingPositionsParams,
) {
  const searchParams = buildSearchParams(params)
  return client.httpClient
    .get<GetPendingPositionsResponse>('position/pending', {
      searchParams,
    })
    .json()
}
