import type { BasicClobClient } from '../createClient'
import type { Tag } from '@prob/types'

export type GetEventTagsResponse = Tag[]

export type GetEventTagsParams = {
  id: string | number
}

export function getEventTags(
  client: BasicClobClient,
  params: GetEventTagsParams,
) {
  return client.publicHttpClient
    .get<GetEventTagsResponse>(`events/${params.id}/tags`)
    .json()
}

