import { getSafeAddress } from '@prob/core'
import { getCode } from 'viem/actions'
import type { BasicClobClient } from '../createClient'

export async function checkSafeProxyWalletExists(
  client: BasicClobClient,
): Promise<boolean> {
  const safeAddress = getSafeAddress(
    client.chainId,
    client.wallet!.account.address,
  )

  return !!(await getCode(client.wallet!, { address: safeAddress }))
}
