import { getOrderTypedData, type OrderStruct } from '@prob/core'
import type {
  SignedOrder,
  UnsignedOrder,
  UnsignedOrderStruct,
} from '../../order/types'
import type { BasicClobClient } from '../createClient'

export async function signOrderStruct(
  client: BasicClobClient,
  order: UnsignedOrderStruct,
): Promise<OrderStruct> {
  const signature = await client.wallet!.signTypedData(
    getOrderTypedData(client.chainId, order),
  )

  return {
    ...order,
    signature,
  }
}

export async function signOrder(
  client: BasicClobClient,
  order: UnsignedOrder,
): Promise<SignedOrder> {
  const orderStruct = await signOrderStruct(client, order)

  return {
    ...orderStruct,
    timeInForce: order.timeInForce,
  }
}
