import type { BasicClobClient } from '../createClient'
import type { CancelOrderResponse } from './cancelOrder'

export type CancelOrdersParams = {
  tokenId: string
  orderIds: Array<string | number>
}

export type CancelOrdersResponse = Array<
  CancelOrderResponse & {
    orderListId: number
  }
>

export function cancelOrders(
  client: BasicClobClient,
  params: CancelOrdersParams,
) {
  return client.l2AuthHttpClient
    .delete<CancelOrdersResponse>(`orders/${client.chainId}`, {
      searchParams: {
        tokenId: params.tokenId,
      },
      json: params.orderIds.map(String),
      retry: 0,
    })
    .json()
}
