import { buildSearchParams } from '../../utils/buildSearchParams'
import type { BasicClobClient } from '../createClient'

export type GetTradesParams = {
  tokenId: string
  beforeTimestamp?: number
  afterTimestamp?: number
  nextCursor?: string
  limit?: number // default 10
}

export type GetTradesResponse = {
  trades: Array<{
    id: string
    orderId: string
    symbol: string
    price: string
    qty: string
    quoteQty: string
    commission: string
    commissionAsset: string
    time: number
    buyer: string
    maker: string
    counterpartyId: number
    propertyName: string
  }>
  next_cursor: string
}

export function getTrades(
  client: BasicClobClient,
  params: GetTradesParams,
) {
  const searchParams = buildSearchParams(params)
  return client.l2AuthHttpClient
    .get<GetTradesResponse>(`trade/${client.chainId}`, {
      searchParams,
    })
    .json()
}

// @TODO: @ChefJerry migrate to domain type
function transformTradesResponse(
  response: GetTradesResponse,
): GetTradesResponse {
  return response
}
