import type { BasicClobClient } from '../createClient'

export type GetOpenOrdersPaginationParams = {
  limit?: number
  page?: number
}

export type GetOpenOrdersParams =
  | ({
      eventId?: string
      tokenIds?: never
    } & GetOpenOrdersPaginationParams)
  | ({
      eventId?: never
      tokenIds?: string[]
    } & GetOpenOrdersPaginationParams)

export type OrderResponse = {
  orderId: number
  clientOrderId: string
  symbol: string
  side: 'BUY' | 'SELL'
  type: string
  timeInForce: string
  price: string
  origQty: string
  executedQty: string
  cumQuote: string
  status: string // @TODO: @ChefJerry add enum
  time: number
  updateTime: number
  avgPrice: string
  origType: string
  tokenId: string
  ctfTokenIf: string
  stopPrice: string
  orderListId: number
  cumQty: string
}

export type GetOpenOrdersResponse = Array<OrderResponse>

export function getOpenOrders(client: BasicClobClient, params?: GetOpenOrdersParams) {
  return client.l2AuthHttpClient
    .get<GetOpenOrdersResponse>(`orders/${client.chainId}/open`, {
      searchParams: {
        ...(typeof params === 'object' && 'eventId' in params ? { eventId: params.eventId } : {}),
        ...(typeof params === 'object' && 'tokenIds' in params ? { token_ids: params.tokenIds?.join(',') } : {}),
      },
    })
    .json()
}
