import { addresses, mergePositionsCalldata } from '@prob/core'
import { numberToHex, parseUnits } from 'viem'
import type { BasicClobClient } from '../createClient'
import { proxyExecuteTx } from '../proxy/proxyExecuteTx'

export type MergePositionParams = {
  conditionId: `0x${string}`
  amount?: bigint
  formattedAmount?: string
} & (
  | {
      amount: bigint
      formattedAmount?: never
    }
  | {
      amount?: never
      formattedAmount: string
    }
)

export function mergePosition(
  client: BasicClobClient,
  params: MergePositionParams,
) {
  const calldata = createMergePositionCalldata(client, params)
  return proxyExecuteTx(client, {
    to: addresses[client.chainId].conditionalTokens,
    data: calldata,
  })
}

export function createMergePositionCalldata(
  client: BasicClobClient,
  params: MergePositionParams,
) {
  const collateralToken = client.exchangeConfig.collateralToken
  const collateralDecimals = client.exchangeConfig.collateralTokenDecimals

  const amount =
    params.amount ?? parseUnits(params.formattedAmount, collateralDecimals)

  return mergePositionsCalldata({
    collateralToken,
    parentCollectionId: numberToHex(0, { size: 32 }),
    conditionId: params.conditionId,
    partition: [1n, 2n],
    amount,
  })
}
