import type { Side } from '@prob/types'
import type { BasicClobClient } from '../createClient'

export type GetPriceParams = {
  tokenId: string
  side: Side
}

export type GetPriceResponse = {
  price: string
}

export function getPrice(client: BasicClobClient, params: GetPriceParams) {
  return client.httpClient
    .get<GetPriceResponse>(`price`, {
      searchParams: {
        token_id: params.tokenId,
        side: params.side,
      },
    })
    .json()
}
