import { WebSocketManager } from '../core/WebSocketManager'
import type {
  WebSocketRequest,
  WebSocketResponse,
  StreamDataEventType,
  StreamDataEvent,
  StreamDataEventHandler,
  ExecutionReportEvent,
  OutboundAccountPositionEvent,
  WebSocketMessage,
} from './types'
import { isWebSocketResponse, isExecutionReportEvent, isOutboundAccountPositionEvent } from './types'
import type { BasicClobClient } from '../../clob/createClient'
import type { ClobClient } from '../../clob/createClobClient'

export interface StreamDataConfig {
  apiKey: string
  accountType?: 'eoa' | 'proxy_wallet'
  url: string
  client?: BasicClobClient & Pick<ClobClient, 'generateApiKey' | 'getApiKey'>
}

export class StreamDataManager {
  private static connectionPool = new Map<string, StreamDataManager>()
  private manager: WebSocketManager | null = null
  private listenKey: string | null = null
  private authPromise?: Promise<void>
  private requestIdCounter = 0
  private subscriptions = new Map<string, Set<(data: StreamDataEvent) => void>>()
  private pendingAuthRequests = new Map<
    string,
    {
      resolve: () => void
      reject: (error: Error) => void
      timeout: ReturnType<typeof setTimeout>
    }
  >()
  private authRetryCount = 0
  private readonly MAX_AUTH_RETRIES = 3
  private isHandling401 = false
  private authMaxRetriesReached = false

  constructor(private config: StreamDataConfig) {
    const key = this.getConnectionKey()
    const existing = StreamDataManager.connectionPool.get(key)
    if (existing) {
      return existing
    }
    StreamDataManager.connectionPool.set(key, this)
  }

  private getConnectionKey(): string {
    return `${this.config.url}:${this.config.apiKey}:${this.config.accountType || 'eoa'}`
  }

  async connect(): Promise<void> {
    this.resetAuthState()
    
    if (this.manager?.isConnected()) {
      return
    }

    if (!this.manager) {
      this.manager = new WebSocketManager({
        url: this.config.url,
        heartbeat: {
          interval: 10 * 60 * 1000,
          timeout: 30 * 60 * 1000,
          message: () => this.createPingMessage(),
        },
        messageQueue: {
          enabled: true,
          maxSize: 100,
        },
        onConnect: () => this.authenticate(),
      })

      this.manager.on('message', (message) => {
        this.handleMessage(message as WebSocketMessage)
      })

      this.manager.on('stateChange', (data) => {
        const stateChange = data as { from: string; to: string }
        if (stateChange.to === 'disconnected') {
          this.handleDisconnect()
        }
      })
    }

    return this.manager.connect()
  }

  async reconnect(): Promise<void> {
    const currentApiKey = this.config.client?.credential?.key ?? this.config.apiKey
    if (currentApiKey !== this.config.apiKey) {
      this.config.apiKey = currentApiKey
    }

    this.resetAuthState()

    if (this.manager?.isConnected() && !this.listenKey) {
      return this.authenticate()
    }

    return this.connect()
  }

  private async authenticate(): Promise<void> {
    if (this.authPromise) {
      return this.authPromise
    }

    this.authPromise = new Promise((resolve, reject) => {
      const requestId = this.generateRequestId()

      const timeout = setTimeout(() => {
        this.pendingAuthRequests.delete(requestId)
        this.authPromise = undefined
        reject(new Error('Authentication timeout after 10s'))
      }, 10000)

      this.pendingAuthRequests.set(requestId, { resolve, reject, timeout })

      const authRequest: WebSocketRequest = {
        id: requestId,
        method: 'userDataStream.start',
        params: {
          apiKey: this.config.apiKey,
          address: this.config.client?.wallet?.account?.address ?? '',
          accountType: this.config.accountType || 'eoa',
        },
      }

      this.manager!.send(authRequest)
    })

    return this.authPromise
  }

  private async handle401Error(msg: WebSocketResponse): Promise<void> {
    const client = this.config.client
    if (!client?.generateApiKey || typeof window !== 'undefined' || !client.wallet) {
      throw new Error(msg.error?.message || 'Authentication failed: 401')
    }

    if (this.isHandling401) {
      return
    }
    console.log('handle401Error', this.authRetryCount, this.MAX_AUTH_RETRIES)

    if (this.authRetryCount >= this.MAX_AUTH_RETRIES) {
      this.handleMaxRetriesReached()
      return
    }

    this.isHandling401 = true
    this.authRetryCount++

    try {
      await this.refreshApiKeyAndRetry(client)
    } catch (error: any) {
      this.isHandling401 = false
      throw error
    }
  }

  private async refreshApiKeyAndRetry(
    client: BasicClobClient & Pick<ClobClient, 'generateApiKey' | 'getApiKey'>,
  ): Promise<void> {
    if (client.getApiKey) {
      try {
        const existingCreds = await client.getApiKey()
        this.config.apiKey = existingCreds.apiKey
        this.isHandling401 = false
        await this.authenticate()
        return
      } catch (error) {
        // Fall through to generateApiKey
      }
    }

    try {
      const newCreds = await client.generateApiKey()
      this.config.apiKey = newCreds.key
      this.isHandling401 = false
      await this.authenticate()
    } catch (error: any) {
      if (error?.data?.error?.code === 'PAS-4001' && 
          error?.data?.error?.message?.includes('already exists')) {
        if (client.getApiKey) {
          const existingCreds = await client.getApiKey()
          this.config.apiKey = existingCreds.apiKey
          this.isHandling401 = false
          await this.authenticate()
          return
        }
      }
      throw error
    }
  }

  private handleMaxRetriesReached(): void {
    const error = new Error(`Authentication failed after ${this.MAX_AUTH_RETRIES} retries`)
    this.clearPendingAuthRequests(error)
    this.resetAuthState()
    this.authMaxRetriesReached = true
    this.manager!.emit('authError', error)
    throw error
  }

  private clearPendingAuthRequests(error: Error): void {
    this.pendingAuthRequests.forEach((pending) => {
      clearTimeout(pending.timeout)
      pending.reject(error)
    })
    this.pendingAuthRequests.clear()
  }

  private resetAuthState(): void {
    this.authRetryCount = 0
    this.isHandling401 = false
    this.authMaxRetriesReached = false
  }

  private handleDisconnect(): void {
    this.listenKey = null
    this.authPromise = undefined
    this.clearPendingAuthRequests(new Error('WebSocket disconnected'))
    this.resetAuthState()
  }

  private createPingMessage(): string {
    return JSON.stringify({
      id: this.generateRequestId(),
      method: 'userDataStream.ping',
      params: {
        apiKey: this.config.apiKey,
      },
    } as WebSocketRequest)
  }

  private handleAuthSuccess(msg: WebSocketResponse, pending: { resolve: () => void }): void {
    this.listenKey = msg.result!.listenKey!
    this.resetAuthState()
    this.manager!.emit('ready', { listenKey: this.listenKey, requestId: msg.id })
    this.authPromise = undefined
    pending.resolve()
  }

  private handleAuthFailure(
    msg: WebSocketResponse,
    pending: { resolve: () => void; reject: (error: Error) => void },
  ): void {
    if (this.authMaxRetriesReached) {
      const error = new Error(`Authentication failed after ${this.MAX_AUTH_RETRIES} retries. Please reconnect manually.`)
      this.authPromise = undefined
      pending.reject(error)
      return
    }

    this.authPromise = undefined
    this.handle401Error(msg)
      .then(() => {
        this.authPromise = undefined
        pending.resolve()
      })
      .catch((error) => {
        this.authPromise = undefined
        pending.reject(error)
      })
  }

  private handleMessage(message: WebSocketMessage): void {
    if (isWebSocketResponse(message)) {
      this.handleAuthResponse(message)
      return
    }

    if (!this.listenKey) {
      return
    }

    if (isExecutionReportEvent(message)) {
      this.emit('executionReport', message)
    } else if (isOutboundAccountPositionEvent(message)) {
      this.emit('outboundAccountPosition', message)
    }
  }

  private handleAuthResponse(msg: WebSocketResponse): void {
    if (!msg.id) {
      if (msg.status === 401 && !this.authMaxRetriesReached) {
        this.handle401Error(msg).catch(() => {})
      }
      return
    }

    const pending = this.pendingAuthRequests.get(msg.id)
    if (!pending) {
      if (msg.status === 401 && !this.authMaxRetriesReached) {
        this.handle401Error(msg).catch(() => {})
      }
      return
    }

    clearTimeout(pending.timeout)
    this.pendingAuthRequests.delete(msg.id)

    if (msg.status === 200 && msg.result?.listenKey) {
      this.handleAuthSuccess(msg, pending)
      return
    }

    if (msg.status === 401) {
      this.handleAuthFailure(msg, pending)
      return
    }

    const error = new Error(msg.error?.message || `Failed to start user data stream: ${msg.status}`)
    this.manager!.emit('error', error)
    this.authPromise = undefined
    pending.reject(error)
  }

  subscribe<T extends StreamDataEventType>(
    handler: StreamDataEventHandler<T>,
    eventType?: T,
  ): () => void {
    if (!this.manager?.isConnected()) {
      this.connect().catch(() => {})
    }

    const key = eventType || '*'
    
    if (!this.subscriptions.has(key)) {
      this.subscriptions.set(key, new Set())
    }
    const handlerWrapper = (data: StreamDataEvent) => {
      handler(data as T extends 'executionReport' ? ExecutionReportEvent : T extends 'outboundAccountPosition' ? OutboundAccountPositionEvent : StreamDataEvent)
    }
    this.subscriptions.get(key)!.add(handlerWrapper)

    return () => {
      this.subscriptions.get(key)?.delete(handlerWrapper)

      if (this.subscriptions.get(key)?.size === 0) {
        this.subscriptions.delete(key)
      }
    }
  }

  private emit(channel: string, data: StreamDataEvent): void {
    const channelHandlers = this.subscriptions.get(channel)
    if (channelHandlers && channelHandlers.size > 0) {
      channelHandlers.forEach((handler) => {
        try {
          handler(data)
        } catch (error) {
          console.error('Error in handler for channel', channel, error)
        }
      })
    }

    const allHandlers = this.subscriptions.get('*')
    if (allHandlers && allHandlers.size > 0) {
      allHandlers.forEach((handler) => {
        try {
          handler(data)
        } catch (error) {
          console.error('Error in handler for all channels', channel, error)
        }
      })
    }
  }


  private generateRequestId(): string {
    return `req-${Date.now()}-${++this.requestIdCounter}`
  }

  disconnect(): void {
    this.manager?.disconnect()
    this.manager = null
    this.listenKey = null
    this.subscriptions.clear()
  }

  isConnected(): boolean {
    return (this.manager?.isConnected() ?? false) && this.listenKey !== null
  }

  getListenKey(): string | null {
    return this.listenKey
  }

  getState(): string {
    return this.manager?.getState() ?? 'disconnected'
  }

  on(
    event: 'ready' | 'error' | 'close' | 'authError',
    handler: (data?: unknown) => void,
  ): () => void {
    if (!this.manager) {
      this.connect().catch(() => {})
      if (!this.manager) {
        return () => {}
      }
    }
    return this.manager.on(event, handler)
  }

  getWebSocket(): WebSocket | null {
    return this.manager?.getWebSocket() ?? null
  }
}

