import { BaseError } from './base'

export class L1AuthUnavailableError extends BaseError {
  override name = 'L1AuthUnavailableError'

  constructor() {
    super('L1 authentication is unavailable: signer is not provided')
  }
}

export class L2AuthNotAvailableError extends BaseError {
  override name = 'L2AuthNotAvailableError'

  constructor() {
    super('L2 authentication is not available: API key is not provided')
  }
}
