import type { BasicClobClient } from '../createClient'
import { PublicStreamManager } from '../../ws/publicStream/PublicStreamManager'
import type { OrderBookSummary } from '@prob/types'
import type { StreamDataSubscription, publicStreamEvent } from '../../ws/streamData'
import { WebSocketUrlRequiredError } from '../../errors/websocket'

export function subscribePublicStream<D = OrderBookSummary>(
  client: BasicClobClient,
  streamNames: string | string[],
  handler: (data: D) => void,
): StreamDataSubscription {
  if (!client.wsUrl) {
    throw new WebSocketUrlRequiredError()
  }

  const url = new URL(`${client.wsUrl}/ws`)
  url.searchParams.set('chainId', client.chainId.toString())
  
  const manager = PublicStreamManager.getInstance({
    url: url.toString(),
  })

  if (!manager.isConnected()) {
    manager.connect().catch(() => {})
  }

  const unsubscribe = manager.subscribe(streamNames, handler as (data: any) => void)

  return {
    unsubscribe,
    reconnect: async () => {
      await manager.reconnect()
    },
    on: (event, handler) => {
      if (event === 'ready' && manager.isConnected()) {
        handler({})
      }
      return manager.on(event as publicStreamEvent, handler)
    },
    ws: manager.getWebSocket(),
  }
}
