import BigNumber from 'bignumber.js'

export function roundToStepSize(
  value: number,
  stepSize: number,
  rounding: 'up' | 'down' = 'up',
) {
  return rounding === 'up'
    ? roundUpToStepSize(value, stepSize)
    : roundDownToStepSize(value, stepSize)
}

export function roundUpToStepSize(value: number, stepSize: number) {
  return new BigNumber(value)
    .dividedBy(stepSize)
    .integerValue(BigNumber.ROUND_CEIL)
    .multipliedBy(stepSize)
    .toNumber()
}

export function roundDownToStepSize(value: number, stepSize: number) {
  return new BigNumber(value)
    .dividedBy(stepSize)
    .integerValue(BigNumber.ROUND_FLOOR)
    .multipliedBy(stepSize)
    .toNumber()
}
