import type { BasicClobClient } from '../createClient'

export type GetTokenIdsForEventParams = {
  eventId: number | string
}

export type MarketTokenInfo = {
  marketId: string | number
  ctfTokenIdYes: string
  ctfTokenIdNo: string
  [key: string]: unknown
}

export type GetTokenIdsForEventResponse = MarketTokenInfo[]

export function getTokenIdsForEvent(
  client: BasicClobClient,
  params: GetTokenIdsForEventParams,
) {
  return client.l2AuthHttpClient
    .get<GetTokenIdsForEventResponse>(`info/token-ids-event`, {
      searchParams: {
        eventId: params.eventId.toString(),
      },
    })
    .json()
}

