import type { PositionValue } from '@prob/types'
import type { BasicClobClient } from '../createClient'

export type GetPositionValueParams = {
  user: string
  market?: string | string[]
}

export type GetPositionValueResponse = Array<PositionValue>

export function getPositionValue(
  client: BasicClobClient,
  params: GetPositionValueParams,
) {
  const searchParams = new URLSearchParams()
  Object.entries(params).forEach(([key, value]) => {
    if (value) {
      searchParams.set(
        key,
        Array.isArray(value) ? value.join(',') : value.toString(),
      )
    }
  })
  return client.httpClient
    .get<GetPositionValueResponse>('position/value', {
      searchParams,
    })
    .json()
}
