import { OrderStructSide } from '@prob/core'
import type { SignedOrder, TimeInForce, UnsignedOrder } from '../../order/types'
import type { BasicClobClient } from '../createClient'
import { signOrder } from './signOrder'

export type PostOrderResponse =
  | {
      orderId: number
      clientOrderId?: string
      symbol: string
      side: 'BUY' | 'SELL'
      type: string
      timeInForce?: string
      price: string
      origQty: string
      executedQty: string
      cumQuote: string
      status: string
      time?: number
      updateTime: number
      avgPrice?: string
      origType?: string
      tokenId: string
      ctfTokenId?: string
      stopPrice?: string
      orderListId?: number
      cumQty?: string
    }
  | {
      code: number
      msg: string
    }

export type PostSignedOrderBody = {
  deferExec: true
  order: {
    expiration: string
    feeRateBps: string
    maker: string
    makerAmount: string
    nonce: string
    salt: string
    side: 'BUY' | 'SELL'
    signature: string
    signatureType: number
    signer: string
    taker: string
    takerAmount: string
    tokenId: string
  }
  owner: string
  orderType: TimeInForce
  slippageTolerance?: {
    minPrice?: string
  }
}

export async function postSignedOrder(
  client: BasicClobClient,
  order: SignedOrder,
) {
  return client.l2AuthHttpClient
    .post<PostOrderResponse>(`order/${client.chainId}`, {
      json: {
        deferExec: true,
        order: {
          salt: order.salt.toString(),
          maker: order.maker,
          signer: order.signer,
          taker: order.taker,
          tokenId: order.tokenId.toString(),
          makerAmount: order.makerAmount.toString(),
          takerAmount: order.takerAmount.toString(),
          side: order.side === OrderStructSide.Buy ? 'BUY' : 'SELL',
          expiration: order.expiration.toString(),
          nonce: order.nonce.toString(),
          feeRateBps: order.feeRateBps.toString(),
          signatureType: order.signatureType,
          signature: order.signature,
        },
        owner: order.signer,
        orderType: order.timeInForce,
        ...(order.priceLimit !== undefined && order.priceLimit > 0
          ? {
              slippageTolerance: {
                minPrice: order.priceLimit.toString(),
              },
            }
          : {}),
      } satisfies PostSignedOrderBody,
    })
    .json()
}

export async function postOrder(client: BasicClobClient, order: UnsignedOrder) {
  const signedOrder = await signOrder(client, order)

  return postSignedOrder(client, signedOrder)
}
