import type { MarketPrice, PriceHistoryInterval } from '@prob/types'
import { buildSearchParams } from '../../utils/buildSearchParams'
import type { BasicClobClient } from '../createClient'

export type GetPricesHistoryParams = {
  market: string
  startTs?: number
  endTs?: number
  interval?: PriceHistoryInterval
  fidelity?: number
}

export type GetPricesHistoryResponse = {
  history: Array<MarketPrice>
}

export function getPricesHistory(
  client: BasicClobClient,
  params: GetPricesHistoryParams,
) {
  const { market, ...restParams } = params
  const searchParams = buildSearchParams(restParams, { market })

  return client.httpClient
    .get<GetPricesHistoryResponse>(`prices-history`, {
      searchParams,
    })
    .json()
}
