/**
 * Manages public WebSocket stream connections and message handling
 * Reuses connections by URL, handles SUBSCRIBE/UNSUBSCRIBE requests and responses,
 * message parsing and data distribution, connection lifecycle management (delayed close when no subscriptions)
 */
import { WebSocketManager } from '../core/WebSocketManager'
import type { OrderBookSummary } from '@prob/types'
import { StreamSubscriptionManager } from './StreamSubscriptionManager'

export interface PublicStreamConfig {
  url: string
  batchDelay?: number
}

interface SubscribeResponse {
  id: number
  status?: number
  result: null | boolean
}

type StreamHandler = (data: OrderBookSummary) => void

export class PublicStreamManager {
  private static instances = new Map<string, PublicStreamManager>()
  private manager: WebSocketManager | null = null
  private subscriptionManager: StreamSubscriptionManager<OrderBookSummary>
  private closeTimer: ReturnType<typeof setTimeout> | null = null
  private requestId = 0
  private pendingRequests = new Map<
    number,
    {
      resolve: () => void
      reject: (error: Error) => void
      timeout: ReturnType<typeof setTimeout>
      streams: string[]
      receivedStreams: Set<string>
    }
  >()

  private constructor(private config: PublicStreamConfig) {
    this.subscriptionManager = new StreamSubscriptionManager<OrderBookSummary>({
      batchDelay: this.config.batchDelay,
      onSubscribeRequest: (streams) => {
        this.sendSubscribeRequest(streams).catch(() => {})
      },
      onUnsubscribeRequest: (streams) => {
        this.sendUnsubscribeRequest(streams).catch(() => {})
        this.checkAndScheduleClose()
      },
    })
  }

  static getInstance(config: PublicStreamConfig): PublicStreamManager {
    const key = config.url
    if (!PublicStreamManager.instances.has(key)) {
      PublicStreamManager.instances.set(key, new PublicStreamManager(config))
    }
    return PublicStreamManager.instances.get(key)!
  }

  subscribe(streamNames: string | string[], handler: StreamHandler): () => void {
    this.cancelScheduledClose()
    this.ensureConnection()

    const unsubscribe = this.subscriptionManager.subscribe(streamNames, handler)

    return () => {
      unsubscribe()
      this.checkAndScheduleClose()
    }
  }

  async connect(): Promise<void> {
    if (this.manager?.isConnected()) {
      return
    }

    if (!this.manager) {
      this.initializeWebSocketManager()
    }

    return this.manager!.connect()
  }

  async reconnect(): Promise<void> {
    return this.connect()
  }

  disconnect(): void {
    this.manager?.disconnect()
    this.manager = null
    this.subscriptionManager.clear()
    this.clearTimers()
  }

  isConnected(): boolean {
    return this.manager?.isConnected() ?? false
  }

  on(
    event: 'ready' | 'error' | 'close',
    handler: (data?: unknown) => void,
  ): () => void {
    if (!this.manager) {
      this.connect().catch(() => {})
      if (!this.manager) {
        return () => {}
      }
    }
    return this.manager.on(event, handler)
  }

  getWebSocket(): WebSocket | null {
    return this.manager?.getWebSocket() ?? null
  }

  private async sendSubscribeRequest(streams: string[]): Promise<void> {
    return new Promise((resolve, reject) => {
      const requestId = ++this.requestId

      const timeout = setTimeout(() => {
        this.pendingRequests.delete(requestId)
        reject(new Error('Subscribe timeout'))
      }, 10000)

      this.pendingRequests.set(requestId, {
        resolve,
        reject,
        timeout,
        streams,
        receivedStreams: new Set(),
      })

      this.manager!.send({
        id: requestId,
        method: 'SUBSCRIBE',
        params: streams,
      })

    })
  }

  private async sendUnsubscribeRequest(streams: string[]): Promise<void> {
    return new Promise((resolve) => {
      const requestId = ++this.requestId
      this.manager!.send({
        id: requestId,
        method: 'UNSUBSCRIBE',
        params: streams,
      })
      resolve()
    })
  }

  private handleMessage(message: string): void {
    try {
      const rawData = typeof message === 'string' ? JSON.parse(message) : message

      if ('id' in rawData && 'result' in rawData) {
        this.handleSubscribeResponse(rawData as SubscribeResponse)
        return
      }

      if ('stream' in rawData && rawData.stream) {
        const streamName = rawData.stream as string
        this.subscriptionManager.emit(streamName, rawData.data)
      }
    } catch (error) {
      console.error('Failed to parse message:', error)
    }
  }

  private handleSubscribeResponse(msg: SubscribeResponse): void {
    const pending = this.pendingRequests.get(msg.id)
    if (!pending) {
      return
    }

    clearTimeout(pending.timeout)
    this.pendingRequests.delete(msg.id)

    const isSuccess = msg.status === 200

    if (!isSuccess) {
      pending.reject(new Error(`Subscribe failed: status=${msg.status}, result=${msg.result}`))
      return
    }

    pending.streams.forEach((stream) => {
      pending.receivedStreams.add(stream)
      this.subscriptionManager.markSubscribed(stream)
    })

    pending.resolve()
  }

  private initializeWebSocketManager(): void {
    this.manager = new WebSocketManager({
      url: this.config.url,
      messageQueue: {
        enabled: true,
        maxSize: 100,
      },
      onConnect: () => {
        this.manager!.emit('ready', {})
      },
    })

    this.manager.on('message', (message) => {
      this.handleMessage(message as any)
    })

    this.manager.on('stateChange', (data) => {
      const stateChange = data as { from: string; to: string }
      if (stateChange.to === 'disconnected') {
        this.handleDisconnect()
      }
    })
  }

  private ensureConnection(): void {
    if (!this.manager?.isConnected()) {
      this.connect().catch(() => {})
    }
  }

  private handleDisconnect(): void {
    this.pendingRequests.forEach((pending) => {
      clearTimeout(pending.timeout)
      pending.reject(new Error('WebSocket disconnected'))
    })
    this.pendingRequests.clear()

    this.subscriptionManager.clear()
    this.clearTimers()
  }

  private clearTimers(): void {
    this.cancelScheduledClose()
  }

  private checkAndScheduleClose(): void {
    if (this.subscriptionManager.hasActiveSubscriptions() || !this.manager?.isConnected()) {
      return
    }

    this.scheduleClose()
  }

  private scheduleClose(): void {
    if (this.closeTimer) {
      return
    }

    this.closeTimer = setTimeout(() => {
      this.closeTimer = null

      if (!this.subscriptionManager.hasActiveSubscriptions() && this.manager?.isConnected()) {
        this.manager.disconnect()
        this.manager = null
      }
    }, 10000)
  }

  private cancelScheduledClose(): void {
    if (this.closeTimer) {
      clearTimeout(this.closeTimer)
      this.closeTimer = null
    }
  }
}
