import type { BasicClobClient } from '../createClient'
import type { OrderResponse } from './getOpenOrders'

export type CancelOrderParams = {
  orderId: string | number
  tokenId: string
}

// @TODO: @ChefJerry transform to domain type
export type CancelOrderResponse = OrderResponse

export function cancelOrder(
  client: BasicClobClient,
  params: CancelOrderParams,
) {
  return client.l2AuthHttpClient
    .delete<CancelOrderResponse>(`order/${client.chainId}/${params.orderId}`, {
      searchParams: {
        tokenId: params.tokenId,
      },
    })
    .json()
}
