import type { BasicClobClient } from '../createClient'
import type { RawMarketData } from './types'

export type GetMarketByIdParams = {
  id: string | number
}

export type GetMarketByIdResponse = RawMarketData

export function getMarketById(
  client: BasicClobClient,
  params: GetMarketByIdParams,
) {
  return client.publicHttpClient
    .get<GetMarketByIdResponse>(`markets/${params.id}`)
    .json()
}
