import BigNumberJS from 'bignumber.js'
import type { BasicClobClient } from '../clob/createClient'
import { calculatePrice } from './calculatePrice'
import { MarketTimeInForce, OrderSide, type LimitUnsignedOrder, type MarketUnsignedOrder, type UnsignedOrder } from './types'

export type CalculateFeeByRateParams = {
  feeRateBps: number | bigint
  outcomeTokens: number | bigint
  makerAmount: bigint
  takerAmount: bigint
  side: OrderSide
  decimals: number // Collateral token decimals
  price?: bigint // Optional price. If provided, use it instead of calculating from makerAmount/takerAmount
}

const BPS_DIVISOR = BigInt(1e4)

type OrderFeeContext = {
  makerAmount: bigint
  takerAmount: bigint
  side: OrderSide
  price: bigint
  pricePerShare: number
  outcomeTokens: bigint
  decimals: number
}

/**
 * Extracts order information and calculates price-related values
 */
function extractOrderFeeContext(
  order: UnsignedOrder,
  exchangeConfig: BasicClobClient['exchangeConfig'],
  pricePerShare?: number,
): OrderFeeContext {
  const { makerAmount, takerAmount, side } = order
  const { collateralTokenDecimals } = exchangeConfig

  const price = calculatePrice({
    makerAmount,
    takerAmount,
    side,
    decimals: collateralTokenDecimals,
  })

  const ONE = new BigNumberJS(10 ** collateralTokenDecimals)
  const priceBN = new BigNumberJS(price.toString())
  const isMarketOrder =
    order.timeInForce === MarketTimeInForce.FOK || order.timeInForce === MarketTimeInForce.FAK

  const actualPricePerShare =
    isMarketOrder && pricePerShare !== undefined
      ? pricePerShare
      : priceBN.dividedBy(ONE).toNumber()

  const outcomeTokens = calculateOutcomeTokens({
    makerAmount,
    takerAmount,
    side,
    isMarketOrder,
    pricePerShare: actualPricePerShare,
    decimals: collateralTokenDecimals,
  })

  return {
    makerAmount,
    takerAmount,
    side,
    price,
    pricePerShare: actualPricePerShare,
    outcomeTokens,
    decimals: collateralTokenDecimals,
  }
}

/**
 * Calculates outcome tokens based on order type and side
 */
function calculateOutcomeTokens({
  makerAmount,
  takerAmount,
  side,
  isMarketOrder,
  pricePerShare,
  decimals,
}: {
  makerAmount: bigint
  takerAmount: bigint
  side: OrderSide
  isMarketOrder: boolean
  pricePerShare: number
  decimals: number
}): bigint {
  if (isMarketOrder && side === OrderSide.Buy) {
    const ONE = new BigNumberJS(10 ** decimals)
    const makerAmountUnscaled = new BigNumberJS(makerAmount.toString()).dividedBy(ONE)
    const tokensUnscaled = makerAmountUnscaled.dividedBy(pricePerShare)
    const tokensRounded = tokensUnscaled.decimalPlaces(1, BigNumberJS.ROUND_DOWN)
    return BigInt(tokensRounded.times(ONE).toFixed(0))
  }

  return side === OrderSide.Buy ? takerAmount : makerAmount
}

/**
 * Calculates the effective fee rate in basis points
 */
function calculateEffectiveFeeRateBps(
  feeMultiplier: number,
  pricePerShare: number,
  minFeeRateBps: bigint,
): number {
  const effectiveFeeRateBps = feeMultiplier * pricePerShare * (1 - pricePerShare) * 100
  return Math.max(effectiveFeeRateBps, Number(minFeeRateBps))
}

/**
 * Calculates the maximum fee for market orders
 * This is used when the exact execution price is unknown
 * Returns fee amount as number (scaled by 10^decimals) to preserve precision
 */
export function calculateFeeByRate(params: CalculateFeeByRateParams): number {
  const { feeRateBps, outcomeTokens, makerAmount, takerAmount, side, decimals, price: providedPrice } = params
  const feeRateBpsBN = new BigNumberJS(feeRateBps)
  const outcomeTokensBN = new BigNumberJS(outcomeTokens)
  const ONE = new BigNumberJS(10 ** decimals)
  const BPS_DIVISOR_BN = new BigNumberJS(BPS_DIVISOR.toString())

  if (feeRateBps <= 0) {
    return 0
  }

  const price = providedPrice !== undefined ? providedPrice : calculatePrice({ makerAmount, takerAmount, side, decimals })
  const priceBN = new BigNumberJS(price.toString())

  if (price <= 0n || priceBN.isGreaterThan(ONE)) {
    return 0
  }

  const ONE_MINUS_PRICE = ONE.minus(priceBN)
  const minPriceBN = priceBN.isLessThanOrEqualTo(ONE_MINUS_PRICE) ? priceBN : ONE_MINUS_PRICE

  let feeAmountBN: BigNumberJS
  if (side === OrderSide.Buy) {
    const numerator = feeRateBpsBN.times(minPriceBN).times(outcomeTokensBN)
    const denominator = priceBN.times(BPS_DIVISOR_BN)
    feeAmountBN = numerator.dividedBy(denominator)
  } else {
    const numerator = feeRateBpsBN.times(minPriceBN).times(outcomeTokensBN)
    const denominator = ONE.times(BPS_DIVISOR_BN)
    feeAmountBN = numerator.dividedBy(denominator)
  }

  return feeAmountBN.toNumber()
}


export function isMarketOrder(order: UnsignedOrder): order is UnsignedOrder & { timeInForce: MarketTimeInForce } {
  return order.timeInForce === MarketTimeInForce.FOK || order.timeInForce === MarketTimeInForce.FAK
}


export type CalculateFeeParams<T extends MarketUnsignedOrder | LimitUnsignedOrder> = 
  T extends MarketUnsignedOrder 
    ? [order: T, pricePerShare: number]
    : [order: T, pricePerShare?: number]

export function calculateFee(
  client: BasicClobClient,
  order: MarketUnsignedOrder,
  pricePerShare: number,
): number

export function calculateFee(
  client: BasicClobClient,
  order: LimitUnsignedOrder,
): number
export function calculateFee(
  client: BasicClobClient,
  order: UnsignedOrder,
  pricePerShare?: number,
): number {
  const { feeMultiplier, minFeeRateBps } = client.exchangeConfig

  const isMarket = isMarketOrder(order)
  if (isMarket && pricePerShare === undefined) {
    throw new Error('pricePerShare is required for market orders')
  }

  const context = extractOrderFeeContext(order, client.exchangeConfig, pricePerShare)
  const finalRateBps = calculateEffectiveFeeRateBps(feeMultiplier, context.pricePerShare, minFeeRateBps)

  const ONE = new BigNumberJS(10 ** context.decimals)
  const priceForFee =
    isMarket && pricePerShare !== undefined
      ? BigInt(Math.floor(context.pricePerShare * Number(ONE)))
      : context.price

  return calculateFeeByRate({
    feeRateBps: finalRateBps,
    outcomeTokens: context.outcomeTokens,
    makerAmount: context.makerAmount,
    takerAmount: context.takerAmount,
    side: context.side,
    decimals: context.decimals,
    price: priceForFee,
  })
}
