import type { OrderStructSignatureType } from '@prob/core'
import type { PartialBy } from 'viem'
import { parseOrder } from '../../order/parseOrder'
import {
  type LimitOrder,
  LimitTimeInForce,
  type LimitUnsignedOrder,
  type MarketOrder,
  MarketTimeInForce,
  type MarketUnsignedOrder,
  type Order,
  type UnsignedOrder,
} from '../../order/types'
import type { BasicClobClient } from '../createClient'

export type CreateOrderOptions = {
  signatureType?: OrderStructSignatureType
}

export async function createOrder(
  client: BasicClobClient,
  order: Order,
): Promise<UnsignedOrder> {
  if (!order.price && order.type !== 'market') {
    throw new Error('price is required')
  }
  if (!order.timeInForce) {
    throw new Error('timeInForce is required')
  }

  return parseOrder(
    {
      ...order,
      signer: order.signer ?? client.wallet?.account?.address!,
      chainId: client.chainId,
      timeInForce: order.timeInForce,
    },
    {
      tradingLimit: client.tradingLimit,
      exchangeConfig: client.exchangeConfig,
    },
  )
}

export type CreateMarketOrderParams = PartialBy<
  MarketOrder,
  'type' | 'timeInForce' | 'priceLimit'
>

export async function createMarketOrder(
  client: BasicClobClient,
  order: CreateMarketOrderParams,
): Promise<MarketUnsignedOrder> {
  const marketOrder: MarketOrder = {
    ...order,
    type: 'market',
    timeInForce: order.timeInForce ?? MarketTimeInForce.FAK,
    price: order.price ?? 0,
    priceLimit: order.priceLimit ?? undefined,
  }

  return createOrder(client, marketOrder as Order) as Promise<MarketUnsignedOrder>
}

export type CreateLimitOrderParams = PartialBy<
  LimitOrder,
  'expiration' | 'type' | 'timeInForce'
>

export async function createLimitOrder(
  client: BasicClobClient,
  order: CreateLimitOrderParams,
): Promise<LimitUnsignedOrder> {
  return createOrder(client, {
    ...order,
    type: 'limit',
    timeInForce: order.timeInForce ?? LimitTimeInForce.GTC,
    expiration: order.expiration ?? 0,
  }) as Promise<LimitUnsignedOrder>
}
