import type {
  Account,
  Address,
  Chain,
  Hex,
  Transport,
  WalletClient,
} from 'viem'
import { signClobAuthEip712 } from '../sign/eip712'
import { getTimestamp } from '../utils/getTimestamp'

export type ProbL1Auth = {
  PROB_ADDRESS: Address
  PROB_SIGNATURE: Hex
  PROB_TIMESTAMP: string
  PROB_NONCE: string
}

export type CreateL1AuthParams = {
  wallet: WalletClient<Transport, Chain, Account>
  chainId: number
  nonce?: number
  timestamp?: number
}

export async function createL1Auth(
  params: CreateL1AuthParams,
): Promise<ProbL1Auth> {
  const timestamp =
    params.timestamp !== undefined ? params.timestamp : getTimestamp()
  const nonce = params.nonce !== undefined ? params.nonce : 0

  const address = params.wallet.account?.address
  if (!address) {
    throw new Error('Wallet address is not defined')
  }

  const signature = await signClobAuthEip712({
    wallet: params.wallet,
    chainId: params.chainId,
    nonce,
    timestamp,
  })

  return {
    PROB_ADDRESS: address,
    PROB_SIGNATURE: signature,
    PROB_TIMESTAMP: timestamp.toString(),
    PROB_NONCE: nonce.toString(),
  }
}
