import type { Side } from '@prob/types'
import type { BasicClobClient } from '../createClient'

export type GetPricesRequestItem = {
  tokenId: string
  side: Side
}

export type GetPricesParams = GetPricesRequestItem[]

export type GetPricesResponse = Record<
  string,
  {
    BUY?: string
    SELL?: string
  }
>

export function getPrices(client: BasicClobClient, params: GetPricesParams) {
  return client.httpClient
    .post<GetPricesResponse>(`prices`, {
      json: params.map(item => ({
        token_id: item.tokenId,
        side: item.side,
      })),
    })
    .json()
}
