import type { BasicClobClient } from '../createClient'
import type { RawMarketData } from './types'

export type GetMarketByPolymarketIdParams = {
  polymarketId: string
}

export type GetMarketByPolymarketIdResponse = RawMarketData

export function getMarketByPolymarketId(
  client: BasicClobClient,
  params: GetMarketByPolymarketIdParams,
) {
  return client.publicHttpClient
    .get<GetMarketByPolymarketIdResponse>(
      `markets/polymarket/${params.polymarketId}`,
    )
    .json()
}
