export type CreateClobClientOptions = Prettify<
  | (Omit<CreateBasicClobClientOptions, 'baseUrl' | 'publicBaseUrl'> & {
    chainId: 56
    baseUrl?: string
    publicBaseUrl?: string
  })
  | (Omit<CreateBasicClobClientOptions, 'chainId'> & {
    chainId: Exclude<number, 56>
  })
>

export type ClobClient = ReturnType<typeof createClobClient>

export function createClobClient(
  options: CreateClobClientOptions = {
    chainId: 56,
    baseUrl: CLOB_BASE_URL,
    publicBaseUrl: PUBLIC_BASE_URL,
  },
) {
  if (options.chainId === 56) {
    options.baseUrl = options.baseUrl ?? CLOB_BASE_URL
    options.publicBaseUrl = options.publicBaseUrl ?? PUBLIC_BASE_URL
  }
  const client = createBasicClobClient(options as CreateBasicClobClientOptions)

  const clobClient = {
    // API Key Authentication
    generateApiKey: (params?: GenerateApiKeyParams) =>
      generateApiKey(client, params),
    getApiKey: () => getApiKey(client),
    deleteApiKey: () => deleteApiKey(client),
    refreshApiKey: () => refreshApiKey(client),
    // order
    createOrder: (order: Order) => createOrder(client, order),
    createMarketOrder: (order: CreateMarketOrderParams) =>
      createMarketOrder(client, order),
    createLimitOrder: (order: CreateLimitOrderParams) =>
      createLimitOrder(client, order),
    signOrder: (order: UnsignedOrder) => signOrder(client, order),
    signOrderStruct: (order: UnsignedOrderStruct) =>
      signOrderStruct(client, order),
    postOrder: (order: UnsignedOrder) => postOrder(client, order),
    postSignedOrder: (order: SignedOrder) => postSignedOrder(client, order),
    postOrders: (orders: UnsignedOrder[]) => postOrders(client, orders),
    postSignedOrders: (orders: SignedOrder[]) =>
      postSignedOrders(client, orders),
    cancelOrder: (params: CancelOrderParams) => cancelOrder(client, params),
    cancelOrders: (params: CancelOrdersParams) => cancelOrders(client, params),
    cancelAllOrders: (params: CancelAllOrdersParams) =>
      cancelAllOrders(client, params),
    getOrder: (params: GetOrderParams) => getOrder(client, params),
    getOpenOrders: (params?: GetOpenOrdersParams) =>
      getOpenOrders(client, params),
    calculateFee: <T extends MarketUnsignedOrder | LimitUnsignedOrder>(
      ...args: CalculateFeeParams<T>
    ): number => {
      const [order, pricePerShare] = args
      if (isMarketOrder(order)) {
        return calculateFeeImpl(
          client,
          order as MarketUnsignedOrder,
          pricePerShare as number,
        )
      } else {
        return calculateFeeImpl(client, order as LimitUnsignedOrder)
      }
    },
    // clob
    getOrderBook: (params: GetOrderBookParams) => getOrderBook(client, params),
    getPrice: (params: GetPriceParams) => getPrice(client, params),
    getPrices: (params: GetPricesParams) => getPrices(client, params),
    getMidpoint: (params: GetMidpointParams) => getMidpoint(client, params),
    getPricesHistory: (params: GetPricesHistoryParams) =>
      getPricesHistory(client, params),
    // positions
    getCurrentPositions: (params: GetCurrentPositionsParams) =>
      getCurrentPositions(client, params),
    getClosedPositions: (params: GetClosedPositionsParams) =>
      getClosedPositions(client, params),
    getPendingPositions: (params: GetPendingPositionsParams) =>
      getPendingPositions(client, params),
    getPositionValue: (params: GetPositionValueParams) =>
      getPositionValue(client, params),
    splitPosition: (params: SplitPositionParams) =>
      splitPosition(client, params),
    createSplitPositionCalldata: (params: SplitPositionParams) =>
      createSplitPositionCalldata(client, params),
    mergePosition: (params: MergePositionParams) =>
      mergePosition(client, params),
    createMergePositionCalldata: (params: MergePositionParams) =>
      createMergePositionCalldata(client, params),
    redeemPosition: (params: RedeemPositionParams) =>
      redeemPosition(client, params),
    createRedeemPositionCalldata: (params: RedeemPositionParams) =>
      createRedeemPositionCalldata(client, params),
    // trades
    getActivity: (params: GetActivityParams) => getActivity(client, params),
    getPnL: (params: GetPnLParams) => getPnL(client, params),
    getTrades: (params: GetTradesParams) => getTrades(client, params),
    // proxy
    checkSafeProxyWalletExists: () => checkSafeProxyWalletExists(client),
    signSafeProxyTx: (params: SignSafeProxyTxParams) =>
      signSafeProxyTx(client.wallet!, params),
    proxyApproveCollateralIfNeeded: (
      params?: ProxyApproveCollateralIfNeededParams,
    ) => proxyApproveCollateralIfNeeded(client, params),
    proxyApproveCollateral: (amount?: bigint) =>
      proxyApproveCollateral(client, amount),
    proxyApproveCollateralSync: (amount?: bigint) =>
      proxyApproveCollateralSync(client, amount),
    proxyExecuteTx: (params: SafeProxyExecuteTxParams) =>
      proxyExecuteTx(client, params),
    getSafeProxyNonce: () => getSafeProxyNonce(client),
    // events
    getEvents: (params?: GetEventsParams) => getEvents(client, params),
    getEventBySlug: (params: GetEventBySlugParams) =>
      getEventBySlug(client, params),
    getEventById: (params: GetEventByIdParams) => getEventById(client, params),
    getEventTags: (params: GetEventTagsParams) => getEventTags(client, params),
    // markets
    getMarkets: (params?: GetMarketsParams) => getMarkets(client, params),
    getMarketById: (params: GetMarketByIdParams) =>
      getMarketById(client, params),
    getMarketByPolymarketId: (params: GetMarketByPolymarketIdParams) =>
      getMarketByPolymarketId(client, params),
    getMarketByBscQuestionId: (params: GetMarketByBscQuestionIdParams) =>
      getMarketByBscQuestionId(client, params),
    // info
    getTokenIdsForEvent: (params: GetTokenIdsForEventParams) =>
      getTokenIdsForEvent(client, params),
    // search
    search: (params: SearchParams) => search(client, params),
    // websocket
    subscribeStreamData: <T extends StreamDataEventType>(
      eventType: T,
      handler: StreamDataEventHandler<T>,
    ) =>
      subscribeStreamData(
        {
          ...client,
          generateApiKey: clobClient.generateApiKey,
          getApiKey: clobClient.getApiKey,
        },
        eventType,
        handler,
        options.onL2AuthError,
      ),
    subscribePublicStream: <D = OrderBookSummary>(
      streamNames: string | string[],
      handler: (data: D) => void,
    ) => subscribePublicStream(client, streamNames, handler),
  }

  return clobClient
}
