import type { BasicClobClient } from '../createClient'
import { buildSearchParams } from '../../utils/buildSearchParams'
import type { UserActivity } from '@prob/types'

export type ActivityType =
  | 'TRADE'
  | 'SPLIT'
  | 'MERGE'
  | 'REDEEM'
  | 'REWARD'
  | 'CONVERSION'

export type ActivitySortBy = 'TIMESTAMP' | 'TOKENS' | 'CASH'

export type ActivitySortDirection = 'ASC' | 'DESC'

export type ActivitySide = 'BUY' | 'SELL'

export type GetActivityParams = {
  user: string
  limit?: number
  offset?: number
  market?: string | string[]
  eventId?: string | number[]
  type?: ActivityType[]
  start?: number
  end?: number
  sortBy?: ActivitySortBy
  sortDirection?: ActivitySortDirection
  side?: ActivitySide
}

export type GetActivityResponse = Array<UserActivity>

export function getActivity(
  client: BasicClobClient,
  params: GetActivityParams,
) {
  const { user, ...restParams } = params
  const searchParams = buildSearchParams(restParams, { user })

  return client.httpClient
    .get<GetActivityResponse>(`activity`, {
      searchParams,
    })
    .json()
}

