import { getSafeAddress } from '@prob/core'
import {
  type Account,
  type Address,
  type Chain,
  type Hex,
  type Transport,
  type TypedDataDomain,
  type WalletClient,
  zeroAddress,
} from 'viem'
import { SafeOperation } from './types'

export type SignSafeProxyTxParams = {
  to: Address
  value?: bigint
  data?: Hex
  operation?: SafeOperation
  safeTxGas?: bigint
  baseGas?: bigint
  gasPrice?: bigint
  gasToken?: Address
  refundReceiver?: Address
  nonce: bigint
}

export const getSafeTxDomain = (
  chainId: number,
  safeAddress: Address,
): TypedDataDomain => ({
  // name: 'Safe',
  // version: '1',
  chainId: chainId,
  verifyingContract: safeAddress,
})

export const EIP712_SAFE_TX_TYPE = {
  // "SafeTx(address to,uint256 value,bytes data,uint8 operation,uint256 safeTxGas,uint256 baseGas,uint256 gasPrice,address gasToken,address refundReceiver,uint256 nonce)"
  SafeTx: [
    { type: 'address', name: 'to' },
    { type: 'uint256', name: 'value' },
    { type: 'bytes', name: 'data' },
    { type: 'uint8', name: 'operation' },
    { type: 'uint256', name: 'safeTxGas' },
    { type: 'uint256', name: 'baseGas' },
    { type: 'uint256', name: 'gasPrice' },
    { type: 'address', name: 'gasToken' },
    { type: 'address', name: 'refundReceiver' },
    { type: 'uint256', name: 'nonce' },
  ],
}

export async function signSafeProxyTx(
  walletClient: WalletClient<Transport, Chain, Account>,
  params: SignSafeProxyTxParams,
) {
  const proxyWalletAddress = getSafeAddress(
    walletClient.chain?.id!,
    walletClient.account?.address!,
  )
  const signature = await walletClient.signTypedData({
    domain: getSafeTxDomain(walletClient.chain?.id!, proxyWalletAddress),
    types: EIP712_SAFE_TX_TYPE,
    primaryType: 'SafeTx',
    message: {
      to: params.to,
      value: params.value ?? 0n,
      data: params.data ?? '0x',
      operation: params.operation ?? BigInt(SafeOperation.Call),
      safeTxGas: params.safeTxGas ?? 0n,
      baseGas: params.baseGas ?? 0,
      gasPrice: params.gasPrice ?? 0,
      gasToken: params.gasToken ?? zeroAddress,
      refundReceiver: params.refundReceiver ?? zeroAddress,
      nonce: params.nonce,
    },
  })
  return signature
}
