import type { BasicClobClient } from '../createClient'
import type { ClobClient } from '../createClobClient'
import { ApiClientError } from '../../errors/api'
import { L2AuthNotAvailableError } from '../../errors/auth'
import { WebSocketUrlRequiredError } from '../../errors/websocket'
import {
  StreamDataManager,
  type StreamDataEventType,
  type StreamDataEventHandler,
  type StreamDataSubscription,
} from '../../ws/streamData'

export function subscribeStreamData<T extends StreamDataEventType>(
  client: BasicClobClient & Pick<ClobClient, 'generateApiKey' | 'getApiKey'>,
  eventType: T,
  handler: StreamDataEventHandler<T>,
  onL2AuthError?: (error: ApiClientError) => void,
): StreamDataSubscription {
  if (!client.wsUrl) {
    throw new WebSocketUrlRequiredError()
  }

  if (!client.credential?.key) {
    throw new L2AuthNotAvailableError()
  }

  const url = new URL(`${client.wsUrl}/ws`)
  url.searchParams.set('chainId', client.chainId.toString())
  
  const manager = new StreamDataManager({
    apiKey: client.credential.key,
    accountType: 'proxy_wallet',
    url: url.toString(),
    client: client as BasicClobClient & Pick<ClobClient, 'generateApiKey' | 'getApiKey'>,
  })

  if (!manager.isConnected()) {
    manager.connect().catch(() => {})
  }

  if (onL2AuthError) {
    manager.on('authError', (error) => {
      const apiError = new ApiClientError({
        status: 401,
        statusText: 'Unauthorized',
        responseBody: {
          error: {
            code: 'PAS-4008',
            message: (error as Error).message || 'Invalid or expired API key',
          },
        },
      })
      onL2AuthError(apiError)
    })
  }

  const unsubscribe = manager.subscribe(handler, eventType)

  return {
    unsubscribe,
    reconnect: async () => {
      await manager.reconnect()
    },
    on: (event, handler) => {
      if (event === 'ready' && manager.isConnected()) {
        handler({ listenKey: manager.getListenKey() })
      }
      return manager.on(event, handler)
    },
    ws: manager.getWebSocket(),
  }
}
