import BigNumberJS from 'bignumber.js'
import { OrderSide } from './types'

export type CalculatePriceParams = {
  makerAmount: bigint
  takerAmount: bigint
  side: OrderSide
  decimals?: number // Optional: collateral token decimals, defaults to 18
  [key: string]: unknown
}

export function calculatePrice(params: CalculatePriceParams): bigint {
  const { makerAmount, takerAmount, side, decimals = 18 } = params
  const precision = BigInt(10 ** decimals)

  if (side === OrderSide.Buy) {
    if (takerAmount === 0n) return 0n
    const result = new BigNumberJS(makerAmount).times(precision.toString()).div(takerAmount)
    const price = BigInt(result.toFixed(0))
    return price
  }

  if (makerAmount === 0n) return 0n
  const result = new BigNumberJS(takerAmount).times(precision.toString()).div(makerAmount)
  const price = BigInt(result.toFixed(0))
  return price
}
