import { getTimestamp } from '../../utils/getTimestamp'
import type { BasicClobClient } from '../createClient'

export type GenerateApiKeyParams = {
  nonce?: number
  timestamp?: number
}

export type GenerateApiKeyResponse = {
  apiKey: string
  secret: string
  passphrase: string
}

export async function generateApiKey(
  client: BasicClobClient,
  params?: GenerateApiKeyParams,
) {
  const { nonce, timestamp } = params ?? {}

  client.nonce = nonce ?? 0
  client.credentialCreatedAt = timestamp ?? getTimestamp()

  const response = await client.l1AuthHttpClient
    .post<GenerateApiKeyResponse>(`auth/api-key/${client.chainId}`)
    .json()

  client.credential = {
    key: response.apiKey,
    secret: response.secret,
    passphrase: response.passphrase,
  }

  return client.credential
}
