import { buildSearchParams } from '../../utils/buildSearchParams'
import type { BasicClobClient } from '../createClient'
import type { PaginationInfo } from '../event/getEvents'
import type { RawMarketData } from './types'

export type GetMarketsParams = {
  page?: number
  limit?: number
  offset?: number
  status?: string
  active?: boolean
  closed?: boolean
  event_id?: number
}

export type GetMarketsResponse = {
  markets: RawMarketData[]
  pagination?: PaginationInfo
}

export function getMarkets(client: BasicClobClient, params?: GetMarketsParams) {
  const searchParams = buildSearchParams(params)

  return client.publicHttpClient
    .get<GetMarketsResponse>(`markets`, {
      searchParams,
    })
    .json()
}
