import { WebSocket } from 'isows'
import type {
  ConnectionState,
  WebSocketEventHandler,
  WebSocketManagerOptions,
} from './types'
import { debugLog } from './debug'

export class WebSocketManager {
  private ws: WebSocket | null = null
  private state: ConnectionState = 'disconnected'
  private heartbeatTimer?: ReturnType<typeof setInterval>
  private heartbeatTimeout?: ReturnType<typeof setTimeout>
  private messageQueue: string[] = []
  private eventHandlers = new Map<string, Set<WebSocketEventHandler>>()
  private options: Required<WebSocketManagerOptions>

  constructor(options: WebSocketManagerOptions) {
    this.options = this.mergeDefaultOptions(options)
  }


  private mergeDefaultOptions(
    options: WebSocketManagerOptions,
  ): Required<WebSocketManagerOptions> {
    return {
      url: options.url,
      heartbeat: {
        interval: options.heartbeat?.interval ?? 30000,
        timeout: options.heartbeat?.timeout ?? 5000,
        message: options.heartbeat?.message ?? JSON.stringify({"id": 0, "method": "ping"}),
      },
      messageQueue: {
        enabled: options.messageQueue?.enabled ?? true,
        maxSize: options.messageQueue?.maxSize ?? 100,
      },
      onConnect: options.onConnect ?? (() => {}),
    }
  }

  async connect(): Promise<void> {
    if (this.state === 'connected' || this.state === 'connecting') {
      return
    }

    this.setState('connecting')

    return new Promise(async (resolve, reject) => {
      try {
        const url =
          typeof this.options.url === 'function'
            ? this.options.url()
            : this.options.url

        this.ws = new WebSocket(url)

        this.ws.onopen = async () => {
          this.setState('connected')

          try {
            await this.options.onConnect()
          } catch (error) {
            reject(error)
            return
          }

          this.startHeartbeat()

          this.processMessageQueue()

          this.emit('connect')
          resolve()
        }

        this.ws.onmessage = (event: MessageEvent) => {
          this.handleMessage(event.data as string)
        }

        this.ws.onerror = () => {
          this.setState('error')
          const errorObj = new Error('WebSocket connection error')
          this.emit('error', errorObj)
          reject(errorObj)
        }

        this.ws.onclose = (event: CloseEvent) => {
          this.setState('disconnected')
          this.stopHeartbeat()
          this.emit('close', { code: event.code, reason: event.reason })
        }
      } catch (error) {
        this.setState('error')
        reject(error)
      }
    })
  }

  disconnect(): void {
    this.stopHeartbeat()

    if (this.ws) {
      this.ws.close()
      this.ws = null
    }

    this.setState('disconnected')
    this.messageQueue = []
  }

  send(message: string | object): void {
    const data =
      typeof message === 'string' ? message : JSON.stringify(message)

    debugLog('send message', data)

    if (this.isConnected()) {
      this.ws!.send(data)
    } else {
      if (this.options.messageQueue.enabled) {
        const maxSize = this.options.messageQueue.maxSize
        if (maxSize && this.messageQueue.length >= maxSize) {
          this.messageQueue.shift()
        }
        this.messageQueue.push(data)
      }
    }
  }

  on(event: string, handler: WebSocketEventHandler): () => void {
    if (!this.eventHandlers.has(event)) {
      this.eventHandlers.set(event, new Set())
    }
    this.eventHandlers.get(event)!.add(handler)

    return () => {
      this.eventHandlers.get(event)?.delete(handler)
    }
  }

  off(event: string, handler: WebSocketEventHandler): void {
    this.eventHandlers.get(event)?.delete(handler)
  }

  emit(event: string, data?: unknown): void {
    this.eventHandlers.get(event)?.forEach((handler) => {
      try {
        handler(data)
      } catch (error) {
        // Handler errors are silently caught to prevent breaking other handlers
        // Errors should be handled within the handler itself
      }
    })
  }

  isConnected(): boolean {
    return (
      this.state === 'connected' && this.ws?.readyState === 1
    )
  }

  getState(): ConnectionState {
    return this.state
  }

  getWebSocket(): WebSocket | null {
    return this.ws
  }

  private setState(state: ConnectionState): void {
    if (this.state !== state) {
      const oldState = this.state
      this.state = state
      this.emit('stateChange', { from: oldState, to: state })
    }
  }

  private handleMessage(data: string): void {
    try {
      debugLog('received rawMessage', data)
      const message = JSON.parse(data)
      this.resetHeartbeatTimeout()
      this.emit('message', message)
    } catch (error) {
      this.emit('error', error)
    }
  }

  private startHeartbeat(): void {
    this.stopHeartbeat()

    this.sendHeartbeat()

    this.heartbeatTimer = setInterval(() => {
      this.sendHeartbeat()
    }, this.options.heartbeat.interval)
  }

  private sendHeartbeat(): void {
  if (!this.isConnected()) {
    return
  }

  const message =
    typeof this.options.heartbeat.message === 'function'
      ? this.options.heartbeat.message()
      : this.options.heartbeat.message!

    this.send(message)
    this.resetHeartbeatTimeout()
}

  private stopHeartbeat(): void {
    if (this.heartbeatTimer) {
      clearInterval(this.heartbeatTimer)
      this.heartbeatTimer = undefined
    }
    if (this.heartbeatTimeout) {
      clearTimeout(this.heartbeatTimeout)
      this.heartbeatTimeout = undefined
    }
  }

  private resetHeartbeatTimeout(): void {
    if (this.heartbeatTimeout) {
      clearTimeout(this.heartbeatTimeout)
    }

    this.heartbeatTimeout = setTimeout(() => {
      // console.log('heartbeat timeout')
      // this.ws?.close()
    }, this.options.heartbeat.timeout)
  }

  private processMessageQueue(): void {
    while (this.messageQueue.length > 0 && this.isConnected()) {
      const message = this.messageQueue.shift()
      if (message) {
        this.ws!.send(message)
      }
    }
  }
}

