import ky, { type KyInstance } from 'ky'
import type {
  Account,
  Chain,
  Transport,
  WalletClient,
} from 'viem'

import type { ExchangeConfig } from '@prob/core'
import { exchangeConfig } from '@prob/core'

import {
  createL1Auth,
  createL2Auth,
} from '../auth'
import { PUBLIC_BASE_URL } from '../constants/baseUrls'
import {
  defaultTradingLimit,
  type TradingLimit,
} from '../constants/tradingLimit'
import { ApiClientError } from '../errors/api'
import {
  L1AuthUnavailableError,
  L2AuthNotAvailableError,
} from '../errors/auth'
import { getTimestamp } from '../utils/getTimestamp'
import { OrderNoLiquidityError } from '../errors/order'

export type BasicClobClient = {
  baseUrl: string
  wsUrl?: string
  chainId: number
  wallet?: WalletClient<Transport, Chain, Account>
  tradingLimit: TradingLimit
  exchangeConfig: ExchangeConfig
  nonce?: number
  credential?: ApiKeyCredential
  credentialCreatedAt?: number
  httpClient: KyInstance
  publicHttpClient: KyInstance
  l1AuthHttpClient: KyInstance
  l2AuthHttpClient: KyInstance
  wsClient?: WebSocket
}

export type ApiKeyCredential = {
  key: string
  secret: string
  passphrase: string
}

export type CreateBasicClobClientOptions = {
  baseUrl: string
  publicBaseUrl?: string
  wsUrl?: string
  chainId: number
  wallet?: WalletClient<Transport, Chain, Account>
  credential?: ApiKeyCredential
  onL2AuthError?: (error: ApiClientError) => void
}

export function createBasicClobClient(options: CreateBasicClobClientOptions) {
  const { baseUrl, publicBaseUrl, wsUrl, chainId, wallet, credential, onL2AuthError } = options

  const httpClient = ky.create({
    prefixUrl: baseUrl,
    headers: {
      'Content-Type': 'application/json',
      ...(typeof window !== 'undefined' ? {} : {'User-Agent': '@prob/clob'}),
      Accept: '*/*',
      Connection: 'keep-alive',
      'Accept-Encoding': 'gzip',
    },
    hooks: {
      beforeError: [
        async error => {
          const { request, response, options } = error
          if (response) {
            const body = await response.json()
            let requestBody: object | undefined

            try {
              requestBody = await request.clone().json()
            } catch {
              // ignore no body POST requests
            }

            if (body && (body as any).error?.code === 'PAS-4206') {
              throw new OrderNoLiquidityError()
            }

            throw new ApiClientError({
              status: response.status,
              statusText: response.statusText,
              responseBody: body,
              method: request.method,
              url: request.url,
              headers: request.headers,
              requestBody,
            })
          }
          return error
        },
      ],
    },
  })

  const publicHttpClient = httpClient.extend({
    prefixUrl: publicBaseUrl ?? PUBLIC_BASE_URL,
  })

  const l1AuthHttpClient = httpClient.extend({
    prefixUrl: baseUrl,
    headers: {
      'Content-Type': 'application/json',
    },
    hooks: {
      beforeRequest: [
        async request => {
          if (!client.wallet || !client.wallet.account) {
            throw new L1AuthUnavailableError()
          }
          const l1Auth = await createL1Auth({
            wallet: client.wallet,
            chainId: client.chainId,
            nonce: client.nonce ?? 0,
          })
          request.headers.set('PROB_ADDRESS', l1Auth.PROB_ADDRESS)
          request.headers.set('PROB_SIGNATURE', l1Auth.PROB_SIGNATURE)
          request.headers.set('PROB_TIMESTAMP', l1Auth.PROB_TIMESTAMP)
          request.headers.set('PROB_NONCE', l1Auth.PROB_NONCE)
        },
      ],
    },
  })

  const l2AuthHttpClient = httpClient.extend({
    hooks: {
      beforeRequest: [
        async (request, options) => {
          if (
            !client.credential ||
            !client.credential.key ||
            !client.credential.secret ||
            !client.credential.passphrase
          ) {
            throw new L2AuthNotAvailableError()
          }
          const requestUrl = new URL(request.url)
          const requestPath = requestUrl.pathname + requestUrl.search
          let body: string | undefined
          try {
            body = await request.clone().json()
            body = JSON.stringify(body)
          } catch {
            // ignore no body request
          }

          const l2Auth = await createL2Auth({
            wallet: client.wallet!,
            credentials: client.credential,
            requestArgs: {
              method: request.method,
              requestPath,
              body,
            }
          })
          request.headers.set('PROB_ADDRESS', l2Auth.PROB_ADDRESS)
          request.headers.set('PROB_SIGNATURE', l2Auth.PROB_SIGNATURE)
          request.headers.set('PROB_TIMESTAMP', l2Auth.PROB_TIMESTAMP)
          request.headers.set('PROB_API_KEY', l2Auth.PROB_API_KEY)
          request.headers.set('PROB_PASSPHRASE', l2Auth.PROB_PASSPHRASE)
        },
      ],
      afterResponse: [
        async (_request, _options, response: Response) => {
          // Check for L2 auth error (invalid/expired API key)
          if (!response.ok && onL2AuthError) {
            try {
              const body = await response.clone().json();
                // Create an ApiClientError for the callback
                const error = new ApiClientError({
                  status: response.status,
                  statusText: response.statusText,
                  responseBody: body,
                  method: _request.method,
                  url: _request.url,
                  headers: _request.headers,
                });
                onL2AuthError(error);
            } catch {
              // Ignore JSON parse errors
            }
          }
          return response
        },
      ]
    },
  })

  const client: BasicClobClient = {
    baseUrl,
    wsUrl,
    chainId,
    wallet,
    tradingLimit: defaultTradingLimit,
    exchangeConfig: exchangeConfig[chainId],
    credential,
    credentialCreatedAt: credential ? getTimestamp() : undefined,
    httpClient,
    publicHttpClient,
    l1AuthHttpClient,
    l2AuthHttpClient,
  }

  return client
}
