import type { BasicClobClient } from '../createClient'

export type CancelAllOrdersParams = {
  tokenId: string
}

export function cancelAllOrders(
  client: BasicClobClient,
  params: CancelAllOrdersParams,
) {
  return client.l2AuthHttpClient
    .delete(`orders/${client.chainId}/all`, {
      searchParams: {
        tokenId: params.tokenId,
      },
      retry: 0,
    })
    .json()
}
