import crypto from 'crypto'

export type SignProbHmacParams = {
  message: string
  secret: string
}

/**
 * Generates a Prob signature using HMAC
 */
export function signProbHmac({ message, secret }: SignProbHmacParams): string {
  const base64Secret = Buffer.from(secret, 'base64')
  const hmac = crypto.createHmac('sha256', base64Secret as unknown as crypto.BinaryLike)
  const sig = hmac.update(message).digest('base64')

  const sigUrlSafe = replaceAll(replaceAll(sig, '+', '-'), '/', '_')

  return sigUrlSafe
}

function replaceAll(s: string, search: string, replace: string) {
  return s.split(search).join(replace)
}
