export { OrderStructSide as OrderSide } from '@prob/core'

import type {
  OrderStructSide as OrderSide,
  OrderStruct,
  OrderStructSignatureType,
} from '@prob/core'
import type { Address, Prettify } from 'viem'

export enum MarketTimeInForce {
  /**
   * FOK - Fill or kill
   * The order must be filled entirely or not at all.
   */
  FOK = 'FOK',
  /**
   * FAK - Fill and kill
   * The order can be partially filled, and any unfilled portion is canceled.
   */
  FAK = 'FAK',
}

export enum LimitTimeInForce {
  /**
   * GTC - Good till cancelled
   */
  GTC = 'GTC',
  /**
   * GTD - Good till date
   */
  GTD = 'GTD',
  /**
   * IOC - Immediate or cancel
   */
  IOC = 'IOC',
}

export type TimeInForce = MarketTimeInForce | LimitTimeInForce

// notional order from user input
export type Order<
  TType extends 'market' | 'limit' | undefined = 'market' | 'limit',
> = {
  chainId?: number
  /**
   * Signer of the order
   */
  signer?: Address
  /**
   * Token ID of the Conditional token asset being traded
   */
  tokenId: string
  /**
   * usd price order to be executed at
   *
   */
  price: number

  /**
   * Order size, denominated in ConditionalToken units
   */
  size?: number

  /**
   * Order value, denominated in CollateralToken units
   */
  value?: number

  /**
   * Side of the order
   */
  side: OrderSide

  /**
   * Nonce used for onchain cancellations
   */
  nonce?: number

  /**
   * Type of the order
   * market or limit
   */
  type: TType

  /**
   * Time in force for the order
   */
  timeInForce?: TimeInForce

  /**
   * Expiration time for the order
   *
   * only for limit orders, unix timestamp in seconds
   */
  expiration?: TType extends 'market' ? never : number

  signatureType?: OrderStructSignatureType

  /**
   * Price slippage tolerance for the order
   *
   * only for market orders
   * if sell order, the price slippage tolerance is the maximum price order will be executed at
   * if buy order, the price slippage tolerance is the minimum price order will be executed at
   */
  priceLimit?: number
}

export type MarketOrder = Prettify<
  Omit<Order<'market' | undefined>, 'price' | 'expiration'> & {
    timeInForce?: MarketTimeInForce
    price?: number
    priceLimit?: number
  }
>

export type LimitOrder = Prettify<
  Order<'limit' | undefined> & { timeInForce: LimitTimeInForce }
>

export type UnsignedOrderStruct = Prettify<Omit<OrderStruct, 'signature'>>

export type UnsignedOrder = Prettify<
  Omit<OrderStruct, 'signature'> & {
    timeInForce: TimeInForce
  }
>

export type MarketUnsignedOrder = Prettify<
  Omit<OrderStruct, 'signature'> & {
    timeInForce: MarketTimeInForce
  }
>

export type LimitUnsignedOrder = Prettify<
  Omit<OrderStruct, 'signature'> & {
    timeInForce: LimitTimeInForce
  }
>

export type SignedOrder = Prettify<
  OrderStruct & {
    timeInForce: TimeInForce
  }
>
