import type { Event, Tag } from '@prob/types'
import { buildSearchParams } from '../../utils/buildSearchParams'
import type { BasicClobClient } from '../createClient'
import type { PaginationInfo } from '../event/getEvents'

export type SearchParams = {
  q: string
  page?: number
  limit?: number
  cache?: boolean
  events_status?: string
  events_tag?: string | string[]
  keep_closed_markets?: string | number
  sort?: string
  ascending?: boolean
  search_tags?: boolean
  recurrence?: string
  exclude_tag_id?: string | string[]
  optimized?: boolean
}

export type SearchResponse = {
  events: Event[]
  tags?: Tag[]
  pagination?: PaginationInfo
}

export function search(client: BasicClobClient, params: SearchParams) {
  const { q, ...restParams } = params
  const searchParams = buildSearchParams(restParams, { q })

  return client.publicHttpClient
    .get<SearchResponse>(`public-search`, {
      searchParams,
    })
    .json()
}
