export interface ExecutionReportEvent {
  e: 'executionReport'
  E: number
  T: number
  u: number
  c: string
  S: 'BUY' | 'SELL'
  o: 'LIMIT' | 'MARKET'
  f: 'GTC' | 'IOC' | 'FOK'
  x: 'NEW' | 'CANCELED' | 'REPLACED' | 'REJECTED' | 'TRADE' | 'EXPIRED'
  X: 'NEW' | 'PARTIALLY_FILLED' | 'FILLED' | 'CANCELED' | 'PENDING_CANCEL' | 'REJECTED' | 'EXPIRED'
  i: number
  t?: number
  m: boolean
  ot: string
  O: number
  ct: string
}

export interface OutboundAccountPositionEvent {
  e: 'outboundAccountPosition'
  E: number
  T: number
  u: number
  m: 'DEPOSIT' | 'WITHDRAWAL' | 'TRADE' | 'OTHER'
  B: Array<{
    a: string
    f: string
    l: string
  }>
}

export interface WebSocketRequest {
  id: string
  method: 'userDataStream.start' | 'userDataStream.ping'
  params: {
    apiKey: string
    address: string
    accountType?: 'eoa' | 'proxy_wallet'
  }
}

export interface WebSocketResponse {
  id?: string
  status?: number
  result?: {
    listenKey: string
  }
  error?: {
    code: number
    message: string
  }
}

export type StreamDataEvent = ExecutionReportEvent | OutboundAccountPositionEvent

export type StreamDataEventType = 'executionReport' | 'outboundAccountPosition'

export type WebSocketMessage = WebSocketResponse | ExecutionReportEvent | OutboundAccountPositionEvent

export function isWebSocketResponse(message: WebSocketMessage): message is WebSocketResponse {
  return 'id' in message && 'status' in message
}

export function isExecutionReportEvent(message: WebSocketMessage): message is ExecutionReportEvent {
  return 'e' in message && message.e === 'executionReport'
}

export function isOutboundAccountPositionEvent(message: WebSocketMessage): message is OutboundAccountPositionEvent {
  return 'e' in message && message.e === 'outboundAccountPosition'
}

export type StreamDataEventHandler<T extends StreamDataEventType> = (
  data: T extends 'executionReport'
    ? ExecutionReportEvent
    : T extends 'outboundAccountPosition'
    ? OutboundAccountPositionEvent
    : StreamDataEvent
) => void


export type publicStreamEvent = 'ready' | 'error' | 'close'
export type privateStreamEvent = 'ready' | 'error' | 'close' | 'authError'
export interface StreamDataSubscription {
  unsubscribe: () => void
  reconnect: () => Promise<void>
  on: (
    event: publicStreamEvent | privateStreamEvent,
    handler: (data?: unknown) => void,
  ) => () => void
  ws: WebSocket | null
}