import type { Account, Address, Chain, Transport, WalletClient } from 'viem'
import { signProbHmac } from '../sign/hmac'
import { getTimestamp } from '../utils/getTimestamp'

export type ProbL2Auth = {
  PROB_ADDRESS: Address
  PROB_SIGNATURE: string
  PROB_TIMESTAMP: string
  PROB_API_KEY: string
  PROB_PASSPHRASE: string
}

export type ApiKeyCredentials = {
  key: string
  secret: string
  passphrase: string
}

export type L2AuthRequestArgs = {
  method: string
  // e.g. /order?tokenId=123, should include query params if present
  requestPath: string
  body?: string
}

export type CreateL2AuthParams = {
  wallet: WalletClient<Transport, Chain, Account>
  credentials: ApiKeyCredentials
  requestArgs: L2AuthRequestArgs
  timestamp?: number
}

// @FIXME: @ChefJerry 
// body and query params should be sorted by key,
// to make sure the message to be signed is the same as the one sent to the server
export async function createL2Auth(
  params: CreateL2AuthParams,
): Promise<ProbL2Auth> {
  const timestamp =
    params.timestamp !== undefined ? params.timestamp : getTimestamp()
  const address = params.wallet.account?.address

  if (!address) {
    throw new Error('Wallet address is not defined')
  }

  let message =
    timestamp +
    params.requestArgs.method.toUpperCase() +
    params.requestArgs.requestPath
  if (params.requestArgs.body !== undefined) {
    message += params.requestArgs.body
  }

  const signature = signProbHmac({ message, secret: params.credentials.secret })

  return {
    PROB_ADDRESS: address,
    PROB_SIGNATURE: signature,
    PROB_TIMESTAMP: timestamp.toString(),
    PROB_API_KEY: params.credentials.key,
    PROB_PASSPHRASE: params.credentials.passphrase,
  }
}
