import type { UserPosition } from '@prob/types'
import type { BasicClobClient } from '../createClient'
import type { GetCurrentPositionsSortBy } from './getCurrentPositions'

export type GetClosedPositionsParams = {
  user?: string
  market?: string | string[]
  title?: string
  eventId?: (number | string) | (number | string)[]
  limit?: number
  offset?: number
  sortBy?: GetCurrentPositionsSortBy
  sortDirection?: 'ASC' | 'DESC'
}

export type GetClosedPositionsResponse = Array<UserPosition>

export function getClosedPositions(
  client: BasicClobClient,
  params: GetClosedPositionsParams,
) {
  const searchParams = new URLSearchParams()
  Object.entries(params).forEach(([key, value]) => {
    if (value) {
      searchParams.set(
        key,
        Array.isArray(value) ? value.join(',') : value.toString(),
      )
    }
  })
  return client.httpClient
    .get<GetClosedPositionsResponse>('position/closed', {
      searchParams,
    })
    .json()
}
