import type { Address, PublicClient, WalletClient } from 'viem'
import { readContract } from 'viem/actions'
import { safeProxyAbi } from './abi'
import type { BasicClobClient } from '../clob/createClient'
import { getSafeAddress } from '@prob/core'

export async function getSafeProxyNonce(
  basicClient: BasicClobClient,
) {
  const safeWalletAddress = getSafeAddress(
    basicClient.chainId,
    basicClient.wallet!.account!.address,
  )
  return getNonce(basicClient.wallet!, safeWalletAddress)
}

export async function getNonce(
  client: PublicClient | WalletClient,
  safeWalletAddress: Address,
) {
  const nonce = await readContract(client, {
    address: safeWalletAddress,
    abi: safeProxyAbi,
    functionName: 'nonce',
  })
  return nonce
}
