import type { BasicClobClient } from '../createClient'

export type GetApiKeyResponse = {
  apiKey: string
  secret: string
  passphrase: string
}

export async function getApiKey(client: BasicClobClient) {
  return client.l1AuthHttpClient
    .get<GetApiKeyResponse>(`auth/api-key/${client.chainId}`)
    .json()
}
