import type { BasicClobClient } from '../createClient'
import type { RawMarketData } from './types'

export type GetMarketByBscQuestionIdParams = {
  bscQuestionId: string
}

export type GetMarketByBscQuestionIdResponse = RawMarketData

export function getMarketByBscQuestionId(
  client: BasicClobClient,
  params: GetMarketByBscQuestionIdParams,
) {
  return client.publicHttpClient
    .get<GetMarketByBscQuestionIdResponse>(
      `markets/bsc/${params.bscQuestionId}`,
    )
    .json()
}
