import { createL2Auth } from "../../auth";
import type { BasicClobClient } from "../createClient";

export type RefreshApiKeyResponse = {
  valid: boolean
}

export async function refreshApiKey(client: BasicClobClient) {
  if (!client.credential || !client.chainId) {
    console.error('Credential or chainId is not set')
    return
  }

  const requestPath = '/auth/verify/l2'
  const method = 'POST'
  const l2Auth = await createL2Auth({
    wallet: client.wallet!,
    credentials: client.credential,
    requestArgs: {
      method,
      requestPath,
    },
  })

  return client.httpClient.post<RefreshApiKeyResponse>('auth/verify/l2', {
    json: {
      chainId: client.chainId,
      method,
      path: requestPath,
    },
    headers: {
      'PROB_ADDRESS': l2Auth.PROB_ADDRESS,
      'PROB_SIGNATURE': l2Auth.PROB_SIGNATURE,
      'PROB_TIMESTAMP': l2Auth.PROB_TIMESTAMP,
      'PROB_API_KEY': l2Auth.PROB_API_KEY,
      'PROB_PASSPHRASE': l2Auth.PROB_PASSPHRASE,
    },
  }).json()
}