/**
 * Generic Stream Subscription Manager
 * Supports array subscription (auto deduplication), reference counting (multiple handlers share the same stream),
 * batch request scheduling (delayed merge of subscribe/unsubscribe requests), data distribution to corresponding handlers
 */
export class StreamSubscriptionManager<T = any> {
  private subscribedStreams = new Set<string>()
  private streamHandlers = new Map<string, Set<(data: T) => void>>()
  private pendingSubscribe = new Set<string>()
  private pendingUnsubscribe = new Set<string>()

  private batchDelay: number 
  private subscribeTimer: ReturnType<typeof setTimeout> | null = null
  private unsubscribeTimer: ReturnType<typeof setTimeout> | null = null

  private onSubscribeRequest?: (streams: string[]) => void
  private onUnsubscribeRequest?: (streams: string[]) => void

  constructor(config: {
    batchDelay?: number
    onSubscribeRequest?: (streams: string[]) => void
    onUnsubscribeRequest?: (streams: string[]) => void
  }) {
    this.batchDelay = config.batchDelay ?? 200
    this.onSubscribeRequest = config.onSubscribeRequest
    this.onUnsubscribeRequest = config.onUnsubscribeRequest
  }

  // Subscribe to streams, returns unsubscribe function
  subscribe(streamNames: string | string[], handler: (data: T) => void): () => void {
    const uniqueStreamNames = this.normalizeStreamNames(streamNames)
    this.addHandlers(uniqueStreamNames, handler)
    this.queueStreamsForSubscription(uniqueStreamNames)

    return this.createUnsubscribeFunction(uniqueStreamNames, handler)
  }

  // Mark stream as successfully subscribed
  markSubscribed(streamName: string): void {
    this.subscribedStreams.add(streamName)
    this.pendingSubscribe.delete(streamName)
  }

  // Mark stream as successfully unsubscribed
  markUnsubscribed(streamName: string): void {
    this.subscribedStreams.delete(streamName)
    this.pendingUnsubscribe.delete(streamName)
  }

  // Emit data to all handlers for the corresponding stream
  emit(streamName: string, data: T): void {
    const handlers = this.streamHandlers.get(streamName)
    if (!handlers || handlers.size === 0) {
      return
    }

    handlers.forEach((handler) => {
      try {
        handler(data)
      } catch (error) {
        console.error('Error in handler for stream', streamName, error)
      }
    })
  }

  hasActiveSubscriptions(): boolean {
    return (
      this.streamHandlers.size > 0 ||
      this.pendingSubscribe.size > 0 ||
      this.subscribedStreams.size > 0
    )
  }

  clear(): void {
    this.subscribedStreams.clear()
    this.pendingSubscribe.clear()
    this.pendingUnsubscribe.clear()
    this.streamHandlers.clear()
    this.clearTimers()
  }

  private normalizeStreamNames(streamNames: string | string[]): string[] {
    const streamNameArray = Array.isArray(streamNames) ? streamNames : [streamNames]
    return Array.from(new Set(streamNameArray))
  }

  // Add handlers for streams
  private addHandlers(streamNames: string[], handler: (data: T) => void): void {
    streamNames.forEach((streamName) => {
      if (!this.streamHandlers.has(streamName)) {
        this.streamHandlers.set(streamName, new Set())
      }
      this.streamHandlers.get(streamName)!.add(handler)
    })
  }

  // Queue streams for subscription
  private queueStreamsForSubscription(streamNames: string[]): void {
    const streamsToSubscribe = streamNames.filter(
      (streamName) =>
        !this.subscribedStreams.has(streamName) && !this.pendingSubscribe.has(streamName),
    )

    if (streamsToSubscribe.length === 0) {
      return
    }

    streamsToSubscribe.forEach((streamName) => {
      this.pendingSubscribe.add(streamName)
    })

    this.scheduleSubscribe()
  }

  // Create unsubscribe function
  private createUnsubscribeFunction(
    streamNames: string[],
    handler: (data: T) => void,
  ): () => void {
    return () => {
      const streamsToUnsubscribe = this.removeHandler(streamNames, handler)
      this.processUnsubscribe(streamsToUnsubscribe)
    }
  }

  // Remove handler, returns streams that need to be unsubscribed
  private removeHandler(streamNames: string[], handler: (data: T) => void): string[] {
    const streamsToUnsubscribe: string[] = []

    streamNames.forEach((streamName) => {
      const handlers = this.streamHandlers.get(streamName)
      if (!handlers) {
        return
      }

      handlers.delete(handler)

      if (handlers.size === 0) {
        this.streamHandlers.delete(streamName)

        if (this.pendingSubscribe.has(streamName)) {
          this.pendingSubscribe.delete(streamName)
        } else if (this.subscribedStreams.has(streamName)) {
          streamsToUnsubscribe.push(streamName)
        }
      }
    })

    return streamsToUnsubscribe
  }

  // Process unsubscribe logic (batch send)
  private processUnsubscribe(streamsToUnsubscribe: string[]): void {
    if (streamsToUnsubscribe.length === 0) {
      return
    }

    streamsToUnsubscribe.forEach((streamName) => {
      this.subscribedStreams.delete(streamName)
      this.pendingUnsubscribe.add(streamName)
    })

    this.scheduleUnsubscribe()
  }

  // Schedule subscribe request (delayed batch send)
  private scheduleSubscribe(): void {
    if (this.subscribeTimer) {
      clearTimeout(this.subscribeTimer)
    }

    this.subscribeTimer = setTimeout(() => {
      this.flushSubscribe()
    }, this.batchDelay)
  }

  // Flush pending subscribe streams
  private flushSubscribe(): void {
    if (this.pendingSubscribe.size === 0) {
      return
    }

    const streams = Array.from(this.pendingSubscribe)
    this.pendingSubscribe.clear()
    this.subscribeTimer = null

    this.onSubscribeRequest?.(streams)
  }

  // Schedule unsubscribe request (delayed batch send)
  private scheduleUnsubscribe(): void {
    if (this.unsubscribeTimer) {
      clearTimeout(this.unsubscribeTimer)
    }

    this.unsubscribeTimer = setTimeout(() => {
      this.flushUnsubscribe()
    }, this.batchDelay)
  }

  // Flush pending unsubscribe streams
  private flushUnsubscribe(): void {
    if (this.pendingUnsubscribe.size === 0) {
      return
    }

    const streams = Array.from(this.pendingUnsubscribe)
    this.pendingUnsubscribe.clear()
    this.unsubscribeTimer = null

    this.onUnsubscribeRequest?.(streams)
  }

  private clearTimers(): void {
    if (this.subscribeTimer) {
      clearTimeout(this.subscribeTimer)
      this.subscribeTimer = null
    }
    if (this.unsubscribeTimer) {
      clearTimeout(this.unsubscribeTimer)
      this.unsubscribeTimer = null
    }
  }
}
