/**
 * Build search params from an object, automatically handling:
 * - undefined/null values (skipped)
 * - numbers and booleans (converted to string)
 * - arrays (joined with comma)
 * - strings (used as-is)
 */
export function buildSearchParams<T extends Record<string, unknown>>(
  params: T | undefined,
  initialParams?: Record<string, string>,
): Record<string, string> {
  const searchParams: Record<string, string> = { ...initialParams }

  if (!params) {
    return searchParams
  }

  for (const [key, value] of Object.entries(params)) {
    if (value === undefined || value === null) {
      continue
    }

    if (Array.isArray(value)) {
      searchParams[key] = value.join(',')
    } else if (typeof value === 'boolean' || typeof value === 'number') {
      searchParams[key] = value.toString()
    } else if (typeof value === 'string') {
      searchParams[key] = value
    } else {
      // Fallback for other types
      searchParams[key] = String(value)
    }
  }

  return searchParams
}
