import { BaseError, type BaseErrorParameters } from './base'

export class ApiClientError extends BaseError {
  override name = 'ApiClientError'
  status: number
  data: string | object | undefined
  code: string | undefined

  constructor(
    args: BaseErrorParameters & {
      url?: string
      status?: number
      statusText?: string
      responseBody?: any
      method?: string
      headers?: Headers
      cause?: Error | BaseError | undefined
      requestBody?: object
    },
  ) {
    const details = {
      url: args.url,
      method: args.method,
      status: args.status,
      statusText: args.statusText,
      headers: args.headers,
      requestBody: args.requestBody,
      responseBody: args.responseBody,
    }

    super(
      `Request failed with status ${args.status} ${args.method?.toUpperCase()} ${args.url}`,
      {
        ...args,
        details,
      },
    )
    this.status = args.status ?? 500
    this.data = args.responseBody
    try {
      this.code = args.responseBody?.error?.code
    } catch {
      this.code = undefined
    }
  }
}
