import {
  type ExchangeConfig,
  getSafeAddress,
  OrderStructSignatureType,
} from '@prob/core'
import BigNumber from 'bignumber.js'
import { type Address, parseUnits, zeroAddress } from 'viem'
import {
  defaultTradingLimit,
  type TradingLimit,
} from '../constants/tradingLimit'
import { roundDownToStepSize, roundUpToStepSize } from '../utils/format'
import { generateSalt } from './generateSalt'
import {
  type Order,
  OrderSide,
  type TimeInForce,
  type UnsignedOrder,
} from './types'

export type ParseOrderOptions = {
  signatureType?: OrderStructSignatureType
  tradingLimit?: TradingLimit
  exchangeConfig: ExchangeConfig
}

export function parseOrder(
  order: Order & {
    signer: Address
    chainId: number
    price: number
    timeInForce: TimeInForce
  },
  options: ParseOrderOptions,
): UnsignedOrder {
  const signatureType =
    order.signatureType ?? OrderStructSignatureType.ProbGnosisSafe
  const { tradingLimit = defaultTradingLimit, exchangeConfig } = options

  const { makerAmount: makerAmountNum, takerAmount: takerAmountNum } =
    order.size
      ? roundOrderPriceAndAmountForSize(
          {
            ...order,
            size: order.size,
          },
          tradingLimit,
        )
      : roundOrderPriceAndAmountForValue({
          ...order,
          value: order.value!,
        })
  const { makerAmount, takerAmount } = parseOrderAmount(
    { makerAmount: makerAmountNum, takerAmount: takerAmountNum },
    exchangeConfig.collateralTokenDecimals,
  )

  return {
    salt: generateSalt(),
    maker:
      signatureType === OrderStructSignatureType.ProbGnosisSafe
        ? getSafeAddress(order.chainId, order.signer)
        : order.signer,
    signer: order.signer,
    taker: zeroAddress,
    tokenId: BigInt(order.tokenId),
    makerAmount,
    takerAmount: order.type === 'market' ? 0n : takerAmount,
    expiration: BigInt(order.expiration ?? 0),
    nonce: BigInt(order.nonce ?? 0),
    feeRateBps: BigInt(exchangeConfig.feeRateBps),
    side: order.side,
    signatureType: signatureType,
    timeInForce: order.timeInForce,
    priceLimit: order.type === 'market' ? order.priceLimit : undefined,
  }
}

export function roundOrderPriceAndAmountForSize(
  order: Order & { chainId: number; price: number; size: number },
  tradingLimit: TradingLimit = defaultTradingLimit,
): {
  price: number
  makerAmount: number
  takerAmount: number
} {
  const price = roundUpToStepSize(order.price, tradingLimit.stepPrice)

  if (order.side === OrderSide.Buy) {
    const takerAmount = roundDownToStepSize(order.size, tradingLimit.stepSize)
    const makerAmount = new BigNumber(takerAmount).times(price).toNumber()
    return {
      takerAmount,
      makerAmount,
      price,
    }
  }

  const makerAmount = roundDownToStepSize(order.size, tradingLimit.stepSize)
  const takerAmount = new BigNumber(makerAmount).times(price).toNumber()
  return {
    takerAmount,
    makerAmount,
    price,
  }
}

export function roundOrderPriceAndAmountForValue(
  order: Order & { chainId: number; price: number; value: number },
  tradingLimit: TradingLimit = defaultTradingLimit,
): {
  price: number
  makerAmount: number
  takerAmount: number
} {
  if (order.type === 'market') {
    if (order.side === OrderSide.Buy) {
      return {
        price: 0,
        makerAmount: roundDownToStepSize(
          order.value,
          tradingLimit.stepPrice * tradingLimit.stepSize,
        ),
        takerAmount: 0, // market order, takerAmount always be 0
      }
    }
    const price = roundUpToStepSize(order.price, tradingLimit.stepPrice)
    const takerAmount = roundDownToStepSize(
      order.value,
      tradingLimit.stepPrice * tradingLimit.stepSize,
    )
    let makerAmount = new BigNumber(takerAmount).dividedBy(price).toNumber()
    makerAmount = roundDownToStepSize(makerAmount, tradingLimit.stepSize)
    return {
      price,
      makerAmount,
      takerAmount: 0, // market order, takerAmount always be 0
    }
  }

  return roundOrderPriceAndAmountForSize({
    ...order,
    value: undefined,
    size: new BigNumber(order.value).dividedBy(order.price).toNumber(),
  })
}
export function parseOrderAmount(
  { makerAmount, takerAmount }: { makerAmount: number; takerAmount: number },
  decimals: number,
) {
  return {
    makerAmount: parseUnits(makerAmount.toString(), decimals),
    takerAmount: parseUnits(takerAmount.toString(), decimals),
  }
}
