import type { OrderBookSummary } from '@prob/types'
import type { BasicClobClient } from '../createClient'

export type GetOrderBookParams = {
  tokenId: string
}

export type GetOrderBookResponse = OrderBookSummary

export function getOrderBook(
  client: BasicClobClient,
  params: GetOrderBookParams,
) {
  return client.httpClient
    .get<GetOrderBookResponse>(`book`, {
      searchParams: {
        token_id: params.tokenId,
      },
    })
    .json()
}
