import type { BasicClobClient } from '../createClient'

// @TODO: rejoin @types order type
export type GetOrderResponse = {
  [key: string]: any
}

export type GetOrderParams = {
  orderId: string | number
  tokenId: string
}

export function getOrder(client: BasicClobClient, params: GetOrderParams) {
  return client.l2AuthHttpClient
    .get<GetOrderResponse>(`orders/${client.chainId}/${params.orderId}`, {
      searchParams: {
        tokenId: params.tokenId,
      },
    })
    .json()
}
