import {
  executeSafeProxyTx,
  type SafeProxyExecuteTxParams,
} from '../../proxy/executeSafeProxyTx'
import type { BasicClobClient } from '../createClient'

export async function proxyExecuteTx(
  client: BasicClobClient,
  params: SafeProxyExecuteTxParams,
) {
  return executeSafeProxyTx(client.wallet!, params)
}
