import type { Event } from '@prob/types'
import { buildSearchParams } from '../../utils/buildSearchParams'
import type { BasicClobClient } from '../createClient'

export type GetEventsParams = {
  page?: number
  limit?: number
  offset?: number
  status?: string
  closed?: boolean
  tag_id?: number
  ascending?: boolean
  related_tags?: boolean
  recurrence?: string
  sort?: string
  order?: string
}

export type PaginationInfo = {
  hasMore?: boolean
  totalResults?: number
  page?: number
  limit?: number
  totalPages?: number
  hasPrevPage?: boolean
}

export type GetEventsResponse = Event[]

export function getEvents(client: BasicClobClient, params?: GetEventsParams) {
  const searchParams = buildSearchParams(params)

  return client.publicHttpClient
    .get<GetEventsResponse>(`events`, {
      searchParams,
    })
    .json()
}
