import type { Event } from '@prob/types'
import type { BasicClobClient } from '../createClient'

export type GetEventByIdParams = {
  id: string | number
}

export type GetEventByIdResponse = Event

export function getEventById(
  client: BasicClobClient,
  params: GetEventByIdParams,
) {
  return client.publicHttpClient
    .get<GetEventByIdResponse>(`events/${params.id}`)
    .json()
}
