import { getSafeAddress } from '@prob/core'
import {
  type Account,
  type Chain,
  type PartialBy,
  type Transport,
  type WalletClient,
  type WriteContractParameters,
  zeroAddress,
} from 'viem'
import { estimateContractGas } from 'viem/actions'
import { safeProxyAbi } from './abi'
import { getSafeProxyExists } from './getSafeProxyExist'
import { getNonce } from './getSafeProxyNonce'
import { type SignSafeProxyTxParams, signSafeProxyTx } from './signSafeProxyTx'
import { SafeOperation } from './types'

export type SafeProxyExecuteTxParams = PartialBy<SignSafeProxyTxParams, 'nonce'>

export async function executeSafeProxyTx(
  walletClient: WalletClient<Transport, Chain, Account>,
  params: SafeProxyExecuteTxParams,
) {
  const {
    to,
    value = 0n,
    data = '0x',
    operation = SafeOperation.Call,
    safeTxGas = 0n,
    baseGas = 0n,
    gasPrice = 0n,
    gasToken = zeroAddress,
    refundReceiver = zeroAddress,
    nonce: _nonce,
  } = params

  const proxyWalletAddress = getSafeAddress(
    walletClient.chain?.id!,
    walletClient.account!.address,
  )

  const proxyWalletExists = await getSafeProxyExists(
    walletClient,
    proxyWalletAddress,
  )
  if (!proxyWalletExists) {
    throw new Error('Safe proxy wallet does not exist')
  }

  const nonce = _nonce ?? (await getNonce(walletClient, proxyWalletAddress))
  if (nonce === undefined) {
    throw new Error('Failed to get nonce')
  }

  const signature = await signSafeProxyTx(walletClient, {
    to,
    value,
    data,
    operation,
    safeTxGas,
    baseGas,
    gasPrice,
    gasToken,
    refundReceiver,
    nonce,
  })
  // console.log('signature', signature)
  if (!signature) {
    throw new Error('Failed to sign transaction')
  }

  let gas: bigint | undefined

  const txParams = {
    address: proxyWalletAddress,
    abi: safeProxyAbi,
    value,
    functionName: 'execTransaction' as const,
    args: [
      to,
      value,
      data,
      operation,
      safeTxGas,
      baseGas,
      gasPrice,
      gasToken,
      refundReceiver,
      signature,
    ] as const,
  }

  try {
    gas = await estimateContractGas(walletClient, txParams)
  } catch (error) {
    console.error('Failed to estimate gas', error)
  }

  const txHash = await walletClient.writeContract({
    ...txParams,
    gas: gas ? (gas * 120n) / 100n : undefined,
  })

  // console.log('txHash', txHash)

  return txHash
}
