import type { BasicClobClient } from '../createClient'

export type GetMidpointParams = {
  typeId: string
}

export type GetMidpointResponse = {
  mid: string
}

export function getMidpoint(
  client: BasicClobClient,
  params: GetMidpointParams,
) {
  return client.httpClient
    .get<GetMidpointResponse>(`midpoint`, {
      searchParams: {
        type_id: params.typeId,
      },
    })
    .json()
}
