import type { Event } from '@prob/types'
import type { BasicClobClient } from '../createClient'

export type GetEventBySlugParams = {
  slug: string
}

export type GetEventBySlugResponse = Event

export function getEventBySlug(
  client: BasicClobClient,
  params: GetEventBySlugParams,
) {
  return client.publicHttpClient
    .get<GetEventBySlugResponse>(`events/slug/${params.slug}`)
    .json()
}

