import {
  type Account,
  type Address,
  type Chain,
  type Hex,
  type Transport,
  type TypedDataDomain,
  verifyTypedData,
  type WalletClient,
} from 'viem'
import {
  CLOB_AUTH_EIP712_MESSAGE,
  CLOB_AUTH_EIP712_NAME,
  CLOB_AUTH_EIP712_TYPES,
  CLOB_AUTH_EIP712_VERSION,
} from '../constants/eip712'

export type SignClobAuthEip712Params = {
  wallet: WalletClient<Transport, Chain, Account>
  chainId: number
  nonce: number
  timestamp: number
}

export async function signClobAuthEip712(
  params: SignClobAuthEip712Params,
): Promise<Hex> {
  const domain: TypedDataDomain = {
    name: CLOB_AUTH_EIP712_NAME,
    version: CLOB_AUTH_EIP712_VERSION,
    chainId: params.chainId,
  }

  return await params.wallet.signTypedData({
    domain,
    primaryType: 'ClobAuth',
    types: CLOB_AUTH_EIP712_TYPES,
    message: {
      address: params.wallet.account?.address,
      timestamp: params.timestamp.toString(),
      nonce: BigInt(params.nonce),
      message: CLOB_AUTH_EIP712_MESSAGE,
    },
  })
}

export type VerifyClobAuthEip712SignatureParams = {
  signature: Hex
  address: Address
  timestamp: number
  nonce: number
}
export async function verifyClobAuthEip712Signature(
  params: VerifyClobAuthEip712SignatureParams,
): Promise<boolean> {
  return await verifyTypedData({
    address: params.address,
    signature: params.signature,
    message: {
      address: params.address,
      timestamp: params.timestamp.toString(),
      nonce: BigInt(params.nonce),
      message: CLOB_AUTH_EIP712_MESSAGE,
    },
    primaryType: 'ClobAuth',
    types: CLOB_AUTH_EIP712_TYPES,
  })
}
