import type { UserPosition } from '@prob/types'
import type { BasicClobClient } from '../createClient'

export type GetCurrentPositionsSortBy = 'REALIZEDPNL' | 'TITLE' | 'PRICE' | 'AVGPRICE' | 'INITIAL' | 'CURRENT' | 'TOKENS'

export type GetCurrentPositionsParams = {
  /** User wallet address (required) */
  user: string
  /** list of condition IDs. */
  market?: string | string[]
  /** filter by market title */
  title?: string
  /** cannot be used with market */
  eventId?: number | string | Array<number|string>
  /** 
   * pagination limit
   * range: 0–500
   *  */
  limit?: number
  /** 
   * pagination offset
   * range: 0–10000
   *  */
  offset?: number
  /** sort by field */
  sortBy?: GetCurrentPositionsSortBy
  sortDirection?: 'ASC' | 'DESC'
  redeemable?: boolean
  sizeThreshold?: number
}

export type GetCurrentPositionsResponse = Array<UserPosition>

export function getCurrentPositions(
  client: BasicClobClient,
  params: GetCurrentPositionsParams,
) {
  const searchParams = new URLSearchParams()
  Object.entries(params).forEach(([key, value]) => {
    if (value) {
      searchParams.set(
        key,
        Array.isArray(value) ? value.join(',') : value.toString(),
      )
    }
  })
  return client.httpClient
    .get<GetCurrentPositionsResponse>('position/current', {
      searchParams,
    })
    .json()
}
